INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('169f9dc0-9c3e-407e-bbf2-037a86380118-ex1', '169f9dc0-9c3e-407e-bbf2-037a86380118', 'reward', 'She got a reward for finding the lost dog.', '她因找到走失的狗而获得了奖赏。'),
  ('169f9dc0-9c3e-407e-bbf2-037a86380118-ex2', '169f9dc0-9c3e-407e-bbf2-037a86380118', 'reward', 'The compensation structure rewarded short-term gains at the expense of stability.', '这种薪酬结构以稳定为代价奖励短期收益。'),
  ('0485f31e-cb85-4fde-8751-b84b63e37131-ex1', '0485f31e-cb85-4fde-8751-b84b63e37131', 'gentle', 'He has a gentle voice.', '他的声音很温和。'),
  ('0485f31e-cb85-4fde-8751-b84b63e37131-ex2', '0485f31e-cb85-4fde-8751-b84b63e37131', 'gentle', 'The court issued a gentle but firm reminder of the evidentiary rules.', '法院发出了温和而坚定的提醒，重申证据规则。'),
  ('fa332c31-09c4-4187-ac8f-ab11157a63fc-ex1', 'fa332c31-09c4-4187-ac8f-ab11157a63fc', 'related', 'These two problems are related.', '这两个问题是相关的。'),
  ('fa332c31-09c4-4187-ac8f-ab11157a63fc-ex2', 'fa332c31-09c4-4187-ac8f-ab11157a63fc', 'related', 'The annual report discloses related-party transactions above the threshold.', '年报披露了超过门槛的关联方交易。'),
  ('21f93549-7f77-401c-a5a9-40bc57f8f610-ex1', '21f93549-7f77-401c-a5a9-40bc57f8f610', 'organ', 'The heart is a vital organ.', '心脏是重要的器官。'),
  ('21f93549-7f77-401c-a5a9-40bc57f8f610-ex2', '21f93549-7f77-401c-a5a9-40bc57f8f610', 'organ', 'The tribunal serves as the principal organ for resolving treaty disputes.', '该法庭是解决条约争端的主要机构。'),
  ('7225f616-d3e6-4670-9565-45686b33d363-ex1', '7225f616-d3e6-4670-9565-45686b33d363', 'lightly', 'Season the soup lightly.', '给汤稍微调点味。'),
  ('7225f616-d3e6-4670-9565-45686b33d363-ex2', '7225f616-d3e6-4670-9565-45686b33d363', 'lightly', 'The court does not lightly disturb a precedent of long standing.', '法院不会轻易推翻一项历史悠久的先例。'),
  ('279a99ed-2822-4597-b6b4-34cb4a5a1323-ex1', '279a99ed-2822-4597-b6b4-34cb4a5a1323', 'concerning', 'I have a question concerning the schedule.', '我有一个关于日程的问题。'),
  ('279a99ed-2822-4597-b6b4-34cb4a5a1323-ex2', '279a99ed-2822-4597-b6b4-34cb4a5a1323', 'concerning', 'The parties exchanged formal notes concerning the interpretation of the annex.', '双方就附件的解释交换了正式照会。'),
  ('25f43d0b-51ca-460a-9bcd-dd0149ac5af8-ex1', '25f43d0b-51ca-460a-9bcd-dd0149ac5af8', 'invent', 'He invented a clever gadget.', '他发明了一个巧妙的小装置。'),
  ('25f43d0b-51ca-460a-9bcd-dd0149ac5af8-ex2', '25f43d0b-51ca-460a-9bcd-dd0149ac5af8', 'invent', 'The defense did not so much explain the discrepancies as invent excuses for them.', '辩方与其说是解释这些差异，不如说是为其编造借口。'),
  ('0e6ced64-3c52-4cca-a813-45fbee853466-ex1', '0e6ced64-3c52-4cca-a813-45fbee853466', 'laughter', 'The room was full of laughter.', '房间里充满了笑声。'),
  ('0e6ced64-3c52-4cca-a813-45fbee853466-ex2', '0e6ced64-3c52-4cca-a813-45fbee853466', 'laughter', 'The proposal met with laughter before circumstances rendered it orthodoxy.', '该提议起初遭人讥笑，后来形势变化却使它成了主流共识。'),
  ('40823abb-292f-460d-b36d-ba9766746cf8-ex1', '40823abb-292f-460d-b36d-ba9766746cf8', 'northwest', 'The wind blows from the northwest.', '风从西北方吹来。'),
  ('40823abb-292f-460d-b36d-ba9766746cf8-ex2', '40823abb-292f-460d-b36d-ba9766746cf8', 'northwest', 'Drought across the northwest depleted reservoirs serving millions.', '西北地区的干旱使为数百万人供水的水库蓄水告急。'),
  ('4bf505ae-c6e7-4bf8-a57e-8f5a2d0b5caa-ex1', '4bf505ae-c6e7-4bf8-a57e-8f5a2d0b5caa', 'counseling', 'The school offers free counseling.', '学校提供免费咨询。'),
  ('4bf505ae-c6e7-4bf8-a57e-8f5a2d0b5caa-ex2', '4bf505ae-c6e7-4bf8-a57e-8f5a2d0b5caa', 'counseling', 'Informed consent followed extensive counseling regarding the trial''s risks.', '在就试验风险进行充分咨询后，参与者签署了知情同意书。'),
  ('d8a3c33b-a8fa-4cb7-8c3b-18872c74f482-ex1', 'd8a3c33b-a8fa-4cb7-8c3b-18872c74f482', 'receiver', 'She picked up the phone receiver.', '她拿起了电话听筒。'),
  ('d8a3c33b-a8fa-4cb7-8c3b-18872c74f482-ex2', 'd8a3c33b-a8fa-4cb7-8c3b-18872c74f482', 'receiver', 'The court-appointed receiver assumed control of the insolvent enterprise.', '法院指定的接管人接管了这家破产企业。'),
  ('5b2ac69e-df6b-4a4c-9eeb-b37ef44de5c2-ex1', '5b2ac69e-df6b-4a4c-9eeb-b37ef44de5c2', 'ritual', 'The ceremony followed an ancient ritual.', '仪式遵循了古老的礼仪。'),
  ('5b2ac69e-df6b-4a4c-9eeb-b37ef44de5c2-ex2', '5b2ac69e-df6b-4a4c-9eeb-b37ef44de5c2', 'ritual', 'The consultation had become a ritual devoid of meaningful influence.', '这种磋商已沦为没有实质影响力的形式。'),
  ('24d0b44c-d4b2-40d2-9872-4384eb26f8f0-ex1', '24d0b44c-d4b2-40d2-9872-4384eb26f8f0', 'insect', 'An insect landed on the flower.', '一只昆虫落在花上。'),
  ('24d0b44c-d4b2-40d2-9872-4384eb26f8f0-ex2', '24d0b44c-d4b2-40d2-9872-4384eb26f8f0', 'insect', 'The decline of insect populations threatens pollination across agricultural systems.', '昆虫数量的减少威胁着整个农业系统的授粉。'),
  ('dfb31402-21b0-4591-a3b0-d7a88daa5d1d-ex1', 'dfb31402-21b0-4591-a3b0-d7a88daa5d1d', 'interrupt', 'Sorry to interrupt your meal.', '抱歉打扰你用餐。'),
  ('dfb31402-21b0-4591-a3b0-d7a88daa5d1d-ex2', 'dfb31402-21b0-4591-a3b0-d7a88daa5d1d', 'interrupt', 'Counsel rose to interrupt before the witness could speculate further.', '在证人进一步推测之前，律师起身打断。'),
  ('46cfda3d-26df-42a4-8919-901cfa1062f4-ex1', '46cfda3d-26df-42a4-8919-901cfa1062f4', 'salmon', 'We had grilled salmon for dinner.', '我们晚餐吃了烤三文鱼。'),
  ('46cfda3d-26df-42a4-8919-901cfa1062f4-ex2', '46cfda3d-26df-42a4-8919-901cfa1062f4', 'salmon', 'The dam would obstruct salmon migration to critical spawning grounds.', '这座大坝会阻断三文鱼洄游至关键的产卵场。'),
  ('1fdd7415-c0fa-4c3c-872c-2a06fe278398-ex1', '1fdd7415-c0fa-4c3c-872c-2a06fe278398', 'trading', 'Trading was busy at the market.', '市场上交易很活跃。'),
  ('1fdd7415-c0fa-4c3c-872c-2a06fe278398-ex2', '1fdd7415-c0fa-4c3c-872c-2a06fe278398', 'trading', 'The exchange suspended trading amid unprecedented volatility.', '面对前所未有的波动，交易所暂停了交易。'),
  ('5cdb20b7-595b-4bf1-b3d4-8a7b97d29387-ex1', '5cdb20b7-595b-4bf1-b3d4-8a7b97d29387', 'magic', 'The children believe in magic.', '孩子们相信魔法。'),
  ('5cdb20b7-595b-4bf1-b3d4-8a7b97d29387-ex2', '5cdb20b7-595b-4bf1-b3d4-8a7b97d29387', 'magic', 'There is no magic formula for a crisis rooted in structural imbalance.', '对于根源在于结构性失衡的危机，并不存在神奇的良方。'),
  ('59f6e5c6-592b-4b0f-b8c9-395b79ea3127-ex1', '59f6e5c6-592b-4b0f-b8c9-395b79ea3127', 'superior', 'This product is superior in quality.', '这款产品质量更优。'),
  ('59f6e5c6-592b-4b0f-b8c9-395b79ea3127-ex2', '59f6e5c6-592b-4b0f-b8c9-395b79ea3127', 'superior', 'The constitution is superior to all inconsistent legislative enactments.', '宪法的效力高于一切与之相抵触的立法。'),
  ('efb79fea-98ee-4f71-9115-73b19f30915d-ex1', 'efb79fea-98ee-4f71-9115-73b19f30915d', 'combat', 'The soldiers trained for combat.', '士兵们为作战进行训练。'),
  ('efb79fea-98ee-4f71-9115-73b19f30915d-ex2', 'efb79fea-98ee-4f71-9115-73b19f30915d', 'combat', 'The convention obliges states to combat the financing of transnational crime.', '该公约要求各国打击跨国犯罪的资金来源。'),
  ('7d4d625f-2427-4354-b4a0-a666eb08f64a-ex1', '7d4d625f-2427-4354-b4a0-a666eb08f64a', 'stem', 'The flower has a long stem.', '这朵花有长长的茎。'),
  ('7d4d625f-2427-4354-b4a0-a666eb08f64a-ex2', '7d4d625f-2427-4354-b4a0-a666eb08f64a', 'stem', 'Many of the challenges stem from decades of deferred investment.', '许多挑战源于数十年来一再推迟的投资。'),
  ('5991e9eb-0dcb-4d7b-b14c-bcd67223683e-ex1', '5991e9eb-0dcb-4d7b-b14c-bcd67223683e', 'surgeon', 'The surgeon performed the operation.', '外科医生做了手术。'),
  ('5991e9eb-0dcb-4d7b-b14c-bcd67223683e-ex2', '5991e9eb-0dcb-4d7b-b14c-bcd67223683e', 'surgeon', 'The licensing board suspended the surgeon pending the malpractice inquiry.', '在医疗事故调查期间，执业委员会暂停了这名外科医生的执照。'),
  ('20bfc787-087e-497c-bdef-c08ffcad4d1a-ex1', '20bfc787-087e-497c-bdef-c08ffcad4d1a', 'acceptable', 'Is this seat acceptable to you?', '这个座位你能接受吗？'),
  ('20bfc787-087e-497c-bdef-c08ffcad4d1a-ex2', '20bfc787-087e-497c-bdef-c08ffcad4d1a', 'acceptable', 'The interim arrangement was deemed acceptable pending the formal review.', '在正式审查之前，临时安排被认为可以接受。'),
  ('580204d8-46fa-404e-96e2-aa03611a7225-ex1', '580204d8-46fa-404e-96e2-aa03611a7225', 'physics', 'She teaches physics at the school.', '她在学校教物理。'),
  ('580204d8-46fa-404e-96e2-aa03611a7225-ex2', '580204d8-46fa-404e-96e2-aa03611a7225', 'physics', 'The breakthrough rewrote assumptions that had governed the physics for decades.', '这一突破改写了主导该物理领域数十年的假设。'),
  ('34ac7d59-82f7-4289-83dd-3ce9af005e82-ex1', '34ac7d59-82f7-4289-83dd-3ce9af005e82', 'rape', 'The crime of rape carries severe penalties.', '强奸罪将面临严厉惩罚。'),
  ('34ac7d59-82f7-4289-83dd-3ce9af005e82-ex2', '34ac7d59-82f7-4289-83dd-3ce9af005e82', 'rape', 'The tribunal characterized the systematic rape as a crime against humanity.', '法庭将系统性强奸认定为危害人类罪。'),
  ('e8939eee-ed76-48c5-8367-62d7be9a7693-ex1', 'e8939eee-ed76-48c5-8367-62d7be9a7693', 'counsel', 'She sought legal counsel.', '她寻求了法律意见。'),
  ('e8939eee-ed76-48c5-8367-62d7be9a7693-ex2', 'e8939eee-ed76-48c5-8367-62d7be9a7693', 'counsel', 'Counsel for the defense moved to exclude the improperly obtained evidence.', '辩方律师申请排除不当取得的证据。'),
  ('4dc60656-8d9a-453d-a419-5d627f4063d4-ex1', '4dc60656-8d9a-453d-a419-5d627f4063d4', 'jeans', 'He wears jeans every day.', '他每天穿牛仔裤。'),
  ('4dc60656-8d9a-453d-a419-5d627f4063d4-ex2', '4dc60656-8d9a-453d-a419-5d627f4063d4', 'jeans', 'The seized jeans bore counterfeit marks of a protected denim label.', '查获的牛仔裤带有受保护牛仔品牌的假冒标识。'),
  ('7207772a-6a25-4ef6-a63d-4e6e582af048-ex1', '7207772a-6a25-4ef6-a63d-4e6e582af048', 'hunt', 'The cat likes to hunt mice.', '这只猫喜欢捕老鼠。'),
  ('7207772a-6a25-4ef6-a63d-4e6e582af048-ex2', '7207772a-6a25-4ef6-a63d-4e6e582af048', 'hunt', 'The treaty restricts the hunt of species listed in its protected annex.', '该条约限制猎捕其保护附件所列物种。'),
  ('99cafc30-f881-41f1-a7af-29a345bc186f-ex1', '99cafc30-f881-41f1-a7af-29a345bc186f', 'continuous', 'The machine makes a continuous hum.', '机器发出持续的嗡嗡声。'),
  ('99cafc30-f881-41f1-a7af-29a345bc186f-ex2', '99cafc30-f881-41f1-a7af-29a345bc186f', 'continuous', 'The facility operates under continuous independent monitoring.', '该设施在持续的独立监测下运营。'),
  ('58d8342c-9539-4f02-bd2f-7b175aaa5d56-ex1', '58d8342c-9539-4f02-bd2f-7b175aaa5d56', 'log', 'He sat on a fallen log.', '他坐在一根倒下的圆木上。'),
  ('58d8342c-9539-4f02-bd2f-7b175aaa5d56-ex2', '58d8342c-9539-4f02-bd2f-7b175aaa5d56', 'log', 'The audit log recorded every access to the privileged records.', '审计日志记录了对特权记录的每一次访问。'),
  ('318b1ccc-19e0-496e-963e-9ab03dfcf84f-ex1', '318b1ccc-19e0-496e-963e-9ab03dfcf84f', 'echo', 'We heard an echo in the cave.', '我们在山洞里听到了回声。'),
  ('318b1ccc-19e0-496e-963e-9ab03dfcf84f-ex2', '318b1ccc-19e0-496e-963e-9ab03dfcf84f', 'echo', 'The dissent echoes warnings the majority chose to ignore.', '这份异议意见呼应了多数意见选择忽视的警告。'),
  ('91b8cd46-a828-4901-a5f5-7879c2cd28f8-ex1', '91b8cd46-a828-4901-a5f5-7879c2cd28f8', 'pill', 'Take one pill before bed.', '睡前服一片药。'),
  ('91b8cd46-a828-4901-a5f5-7879c2cd28f8-ex2', '91b8cd46-a828-4901-a5f5-7879c2cd28f8', 'pill', 'The board swallowed a bitter pill in accepting the structural remedy.', '董事会接受这项结构性救济，无异于吞下一颗苦果。'),
  ('af573dd8-1309-4c65-8214-a9f6302d7cf6-ex1', 'af573dd8-1309-4c65-8214-a9f6302d7cf6', 'excited', 'The kids are excited about the trip.', '孩子们对这次旅行很兴奋。'),
  ('af573dd8-1309-4c65-8214-a9f6302d7cf6-ex2', 'af573dd8-1309-4c65-8214-a9f6302d7cf6', 'excited', 'Investors grew excited about returns the underlying fundamentals could not support.', '投资者对基本面无法支撑的回报变得兴奋起来。'),
  ('b57482ce-25f4-411c-9a0e-c78caa9aa4f1-ex1', 'b57482ce-25f4-411c-9a0e-c78caa9aa4f1', 'sculpture', 'The sculpture stands in the park.', '这座雕塑矗立在公园里。'),
  ('b57482ce-25f4-411c-9a0e-c78caa9aa4f1-ex2', 'b57482ce-25f4-411c-9a0e-c78caa9aa4f1', 'sculpture', 'The sculpture was repatriated after decades of litigation over its provenance.', '在围绕其来源的数十年诉讼后，这座雕塑得以归还。'),
  ('a2a30044-89b3-402f-b9e5-d70d3c4f5d87-ex1', 'a2a30044-89b3-402f-b9e5-d70d3c4f5d87', 'compound', 'Water is a chemical compound.', '水是一种化合物。'),
  ('a2a30044-89b3-402f-b9e5-d70d3c4f5d87-ex2', 'a2a30044-89b3-402f-b9e5-d70d3c4f5d87', 'compound', 'Delay compounds the harm and inflates the eventual cost of remediation.', '拖延加重了损害，并推高了最终的修复成本。'),
  ('61005dde-3c63-4fbc-bffb-e33418f326cd-ex1', '61005dde-3c63-4fbc-bffb-e33418f326cd', 'integrate', 'The app integrates with your calendar.', '这个应用能与你的日历整合。'),
  ('61005dde-3c63-4fbc-bffb-e33418f326cd-ex2', '61005dde-3c63-4fbc-bffb-e33418f326cd', 'integrate', 'The reform integrates mental health services into primary care provision.', '这项改革将心理健康服务整合进初级医疗体系。'),
  ('f3810efe-121a-44cb-8a6d-df5c88254f5a-ex1', 'f3810efe-121a-44cb-8a6d-df5c88254f5a', 'flour', 'Add two cups of flour.', '加两杯面粉。'),
  ('f3810efe-121a-44cb-8a6d-df5c88254f5a-ex2', 'f3810efe-121a-44cb-8a6d-df5c88254f5a', 'flour', 'The import standards apply to every consignment of flour entering the market.', '进口标准适用于进入市场的每一批面粉。'),
  ('43920f75-489f-46a4-8b32-c418b9f4c5af-ex1', '43920f75-489f-46a4-8b32-c418b9f4c5af', 'bitter', 'The coffee tastes bitter.', '这咖啡味道很苦。'),
  ('43920f75-489f-46a4-8b32-c418b9f4c5af-ex2', '43920f75-489f-46a4-8b32-c418b9f4c5af', 'bitter', 'The bitter dispute over the estate spanned three jurisdictions and two decades.', '围绕这笔遗产的激烈纠纷横跨三个司法管辖区，持续了二十年。'),
  ('4991aee7-ba26-429e-9d42-93f145320ebb-ex1', '4991aee7-ba26-429e-9d42-93f145320ebb', 'bare', 'The trees were bare in winter.', '冬天树木光秃秃的。'),
  ('4991aee7-ba26-429e-9d42-93f145320ebb-ex2', '4991aee7-ba26-429e-9d42-93f145320ebb', 'bare', 'The disclosure conveyed the bare minimum the regulation could be read to require.', '这份披露仅传达了法规可被解读为要求的最低限度。'),
  ('d2f6481d-4e49-4bcb-b227-296cbf9e648f-ex1', 'd2f6481d-4e49-4bcb-b227-296cbf9e648f', 'slope', 'We skied down the slope.', '我们滑下了斜坡。'),
  ('d2f6481d-4e49-4bcb-b227-296cbf9e648f-ex2', 'd2f6481d-4e49-4bcb-b227-296cbf9e648f', 'slope', 'The precedent sets the law on a slippery slope toward unchecked discretion.', '这一先例使法律走上了通往不受约束裁量权的滑坡。'),
  ('4042de6c-2d3a-4364-b343-8a03c3783ccf-ex1', '4042de6c-2d3a-4364-b343-8a03c3783ccf', 'rent', 'How much is the monthly rent?', '月租是多少？'),
  ('4042de6c-2d3a-4364-b343-8a03c3783ccf-ex2', '4042de6c-2d3a-4364-b343-8a03c3783ccf', 'rent', 'The ordinance caps annual rent increases for regulated units.', '该条例对受管制单元的年租金涨幅设定上限。'),
  ('c3a172c3-5060-41f6-8ab1-bd06f6f913c7-ex1', 'c3a172c3-5060-41f6-8ab1-bd06f6f913c7', 'presidency', 'His presidency lasted four years.', '他的总统任期持续了四年。'),
  ('c3a172c3-5060-41f6-8ab1-bd06f6f913c7-ex2', 'c3a172c3-5060-41f6-8ab1-bd06f6f913c7', 'presidency', 'The court circumscribed the immunities attaching to the presidency in civil suits.', '法院限定了总统职位在民事诉讼中所享有的豁免。'),
  ('3bb46c6c-f414-4cf1-8ddb-f873b2133e9b-ex1', '3bb46c6c-f414-4cf1-8ddb-f873b2133e9b', 'serving', 'This recipe makes four servings.', '这个食谱可做四人份。'),
  ('3bb46c6c-f414-4cf1-8ddb-f873b2133e9b-ex2', '3bb46c6c-f414-4cf1-8ddb-f873b2133e9b', 'serving', 'The labeling rules require disclosure of sodium content per serving.', '标签规则要求披露每份食品的钠含量。'),
  ('0ec932ef-ea62-41c8-a31e-5c88fe4b84aa-ex1', '0ec932ef-ea62-41c8-a31e-5c88fe4b84aa', 'subtle', 'There is a subtle difference in taste.', '味道上有细微的差别。'),
  ('0ec932ef-ea62-41c8-a31e-5c88fe4b84aa-ex2', '0ec932ef-ea62-41c8-a31e-5c88fe4b84aa', 'subtle', 'The clause effected a subtle but consequential shift in the burden of proof.', '该条款实现了举证责任虽细微却影响深远的转移。'),
  ('0ee005e6-77df-4d5f-b9e9-27fe98ffcb83-ex1', '0ee005e6-77df-4d5f-b9e9-27fe98ffcb83', 'greatly', 'I greatly appreciate your help.', '我非常感谢你的帮助。'),
  ('0ee005e6-77df-4d5f-b9e9-27fe98ffcb83-ex2', '0ee005e6-77df-4d5f-b9e9-27fe98ffcb83', 'greatly', 'The reforms greatly expanded the scope of mandatory disclosure.', '这些改革大大扩展了强制披露的范围。'),
  ('ab129899-ae9c-46e3-941f-cda18d66151c-ex1', 'ab129899-ae9c-46e3-941f-cda18d66151c', 'bishop', 'The bishop led the service.', '主教主持了礼拜。'),
  ('ab129899-ae9c-46e3-941f-cda18d66151c-ex2', 'ab129899-ae9c-46e3-941f-cda18d66151c', 'bishop', 'The diocese disputed the bishop''s authority to dispose of the property.', '教区对主教处置该财产的权限提出了异议。'),
  ('22de68d2-9e98-49e0-b82c-52b2a59885fa-ex1', '22de68d2-9e98-49e0-b82c-52b2a59885fa', 'drinking', 'Drinking water is essential.', '饮用水必不可少。'),
  ('22de68d2-9e98-49e0-b82c-52b2a59885fa-ex2', '22de68d2-9e98-49e0-b82c-52b2a59885fa', 'drinking', 'The regulation restricts drinking establishments within proximity of schools.', '该法规限制在学校附近开设饮酒场所。'),
  ('c539f19e-8733-4e55-9c87-a0f1c7e6cc75-ex1', 'c539f19e-8733-4e55-9c87-a0f1c7e6cc75', 'acceptance', 'Her acceptance into the program delighted her.', '被该项目录取让她很高兴。'),
  ('c539f19e-8733-4e55-9c87-a0f1c7e6cc75-ex2', 'c539f19e-8733-4e55-9c87-a0f1c7e6cc75', 'acceptance', 'Acceptance must mirror the offer precisely to form a binding contract.', '承诺必须与要约完全一致，方能构成有约束力的合同。'),
  ('9ce57c81-ceae-402b-97d7-6b9dde807ae9-ex1', '9ce57c81-ceae-402b-97d7-6b9dde807ae9', 'pump', 'Use the pump to inflate the tire.', '用打气筒给轮胎充气。'),
  ('9ce57c81-ceae-402b-97d7-6b9dde807ae9-ex2', '9ce57c81-ceae-402b-97d7-6b9dde807ae9', 'pump', 'The central bank moved to pump liquidity into a freezing interbank market.', '央行着手向冻结的银行间市场注入流动性。'),
  ('462ade73-28e6-4f3a-9e6c-0f3c76532b84-ex1', '462ade73-28e6-4f3a-9e6c-0f3c76532b84', 'candy', 'The children love candy.', '孩子们喜欢糖果。'),
  ('462ade73-28e6-4f3a-9e6c-0f3c76532b84-ex2', '462ade73-28e6-4f3a-9e6c-0f3c76532b84', 'candy', 'The labeling reforms restrict marketing of candy directed at minors.', '标签改革限制面向未成年人的糖果营销。'),
  ('04d1df7d-679a-448b-a1fe-35b8f9ca9a0e-ex1', '04d1df7d-679a-448b-a1fe-35b8f9ca9a0e', 'evil', 'The story is about good versus evil.', '这个故事讲的是善与恶的对抗。'),
  ('04d1df7d-679a-448b-a1fe-35b8f9ca9a0e-ex2', '04d1df7d-679a-448b-a1fe-35b8f9ca9a0e', 'evil', 'Perfectionism is often the enemy of timely and proportionate regulation, the lesser evil being action.', '完美主义常是及时适度监管的大敌，相比之下采取行动是两害取其轻。'),
  ('90bcf4b9-ed68-459b-80df-b3cb7a1b3236-ex1', '90bcf4b9-ed68-459b-80df-b3cb7a1b3236', 'pleased', 'I am pleased to meet you.', '很高兴见到你。'),
  ('90bcf4b9-ed68-459b-80df-b3cb7a1b3236-ex2', '90bcf4b9-ed68-459b-80df-b3cb7a1b3236', 'pleased', 'The mediator declared herself pleased with the constructive tone of the talks.', '调解人表示对会谈的建设性基调感到满意。'),
  ('ef36596a-a410-4e17-bbc2-0374989fb1bd-ex1', 'ef36596a-a410-4e17-bbc2-0374989fb1bd', 'medal', 'She won a gold medal.', '她赢得了金牌。'),
  ('ef36596a-a410-4e17-bbc2-0374989fb1bd-ex2', 'ef36596a-a410-4e17-bbc2-0374989fb1bd', 'medal', 'The medal was rescinded after the doping violation was confirmed.', '兴奋剂违规被证实后，该奖牌被收回。'),
  ('ae448d0c-e369-45ca-beae-a544212b1b71-ex1', 'ae448d0c-e369-45ca-beae-a544212b1b71', 'beg', 'The dog begged for food.', '那只狗讨要食物。'),
  ('ae448d0c-e369-45ca-beae-a544212b1b71-ex2', 'ae448d0c-e369-45ca-beae-a544212b1b71', 'beg', 'The petitioners beg leave to amend their pleadings in light of new evidence.', '请愿人请求准许根据新证据修改其诉状。'),
  ('db8d4119-091c-46e1-b341-0d34758a968c-ex1', 'db8d4119-091c-46e1-b341-0d34758a968c', 'sponsor', 'A local bank sponsors the team.', '一家本地银行赞助这支球队。'),
  ('db8d4119-091c-46e1-b341-0d34758a968c-ex2', 'db8d4119-091c-46e1-b341-0d34758a968c', 'sponsor', 'The sponsor threatened to withdraw funding absent governance reform.', '赞助方威胁称，若不进行治理改革便撤回资金。'),
  ('5d5654e6-a863-4fe8-bb73-4a6215efca94-ex1', '5d5654e6-a863-4fe8-bb73-4a6215efca94', 'ethical', 'It is the ethical thing to do.', '这样做才合乎道德。'),
  ('5d5654e6-a863-4fe8-bb73-4a6215efca94-ex2', '5d5654e6-a863-4fe8-bb73-4a6215efca94', 'ethical', 'The conduct, though lawful, raised serious ethical concerns.', '这一行为虽然合法，却引发了严重的伦理疑虑。'),
  ('1fb794d2-2949-45d6-988c-7434ba7b763a-ex1', '1fb794d2-2949-45d6-988c-7434ba7b763a', 'secondary', 'She teaches at a secondary school.', '她在一所中学教书。'),
  ('1fb794d2-2949-45d6-988c-7434ba7b763a-ex2', '1fb794d2-2949-45d6-988c-7434ba7b763a', 'secondary', 'The guarantor''s liability is secondary to the primary obligor''s.', '担保人的责任居于主债务人责任之后。'),
  ('78f1a67d-0c9e-4035-8746-9b475a001a24-ex1', '78f1a67d-0c9e-4035-8746-9b475a001a24', 'slam', 'Don''t slam the door.', '不要砰地关门。'),
  ('78f1a67d-0c9e-4035-8746-9b475a001a24-ex2', '78f1a67d-0c9e-4035-8746-9b475a001a24', 'slam', 'Critics slammed the proposal as fiscally reckless and administratively naive.', '批评者抨击该提案在财政上鲁莽、在行政上天真。'),
  ('5958e879-2d6c-49c3-a888-f5b024f6ecb5-ex1', '5958e879-2d6c-49c3-a888-f5b024f6ecb5', 'export', 'The country exports a lot of coffee.', '这个国家出口大量咖啡。'),
  ('5958e879-2d6c-49c3-a888-f5b024f6ecb5-ex2', '5958e879-2d6c-49c3-a888-f5b024f6ecb5', 'export', 'The export of dual-use technology requires authorization under the control regime.', '两用技术的出口须根据管制制度获得授权。'),
  ('68d3d2f4-62b9-4aed-8793-4b5da0dd8d42-ex1', '68d3d2f4-62b9-4aed-8793-4b5da0dd8d42', 'experimental', 'The treatment is still experimental.', '这种疗法仍处于试验阶段。'),
  ('68d3d2f4-62b9-4aed-8793-4b5da0dd8d42-ex2', '68d3d2f4-62b9-4aed-8793-4b5da0dd8d42', 'experimental', 'The experimental design isolated the causal effect through randomized assignment.', '该实验设计通过随机分配分离出了因果效应。'),
  ('89478b51-d1d2-47de-822b-6f088651c82e-ex1', '89478b51-d1d2-47de-822b-6f088651c82e', 'melt', 'The ice cream is starting to melt.', '冰淇淋开始融化了。'),
  ('89478b51-d1d2-47de-822b-6f088651c82e-ex2', '89478b51-d1d2-47de-822b-6f088651c82e', 'melt', 'Apparent consensus melted away once concrete commitments were demanded.', '一旦要求作出具体承诺，表面上的共识便烟消云散。'),
  ('bec49fc5-2b34-43d1-81ce-b2c8f451b44f-ex1', 'bec49fc5-2b34-43d1-81ce-b2c8f451b44f', 'midnight', 'The party lasted until midnight.', '派对一直持续到午夜。'),
  ('bec49fc5-2b34-43d1-81ce-b2c8f451b44f-ex2', 'bec49fc5-2b34-43d1-81ce-b2c8f451b44f', 'midnight', 'The communiqué was released at midnight to coincide with market closures.', '公报在午夜发布，以配合市场收盘。'),
  ('69a290d4-af3c-4fa8-aa2c-d08afa0b246f-ex1', '69a290d4-af3c-4fa8-aa2c-d08afa0b246f', 'curve', 'The road has a sharp curve.', '这条路有一个急弯。'),
  ('69a290d4-af3c-4fa8-aa2c-d08afa0b246f-ex2', '69a290d4-af3c-4fa8-aa2c-d08afa0b246f', 'curve', 'The yield curve inverted, a signal markets read as portending recession.', '收益率曲线倒挂，市场将其视为衰退将至的信号。'),
  ('844158f2-e13e-4949-9bc4-639f17e20e19-ex1', '844158f2-e13e-4949-9bc4-639f17e20e19', 'integrity', 'She is known for her integrity.', '她以正直著称。'),
  ('844158f2-e13e-4949-9bc4-639f17e20e19-ex2', '844158f2-e13e-4949-9bc4-639f17e20e19', 'integrity', 'Auditor integrity is compromised where consulting fees dwarf audit fees.', '当咨询费远超审计费时，审计师的诚信便受到损害。'),
