  ('bd271644-1e8b-4574-8c58-2e1c7e0c93c6-ex2', 'bd271644-1e8b-4574-8c58-2e1c7e0c93c6', 'exclude', 'The court excluded evidence obtained without valid judicial authorization.', '法院排除了未经有效司法授权获取的证据。'),
  ('33686716-044f-4c86-b5b6-4a9943996c25-ex1', '33686716-044f-4c86-b5b6-4a9943996c25', 'harsh', 'The winter was harsh this year.', '今年冬天很严酷。'),
  ('33686716-044f-4c86-b5b6-4a9943996c25-ex2', '33686716-044f-4c86-b5b6-4a9943996c25', 'harsh', 'Even the policy''s harshest critics conceded the early indicators were encouraging.', '连该政策最严厉的批评者也承认早期指标令人鼓舞。'),
  ('df7d9651-253a-480e-af13-e5b6b678cd28-ex1', 'df7d9651-253a-480e-af13-e5b6b678cd28', 'closet', 'Hang your coat in the closet.', '把外套挂进衣橱。'),
  ('df7d9651-253a-480e-af13-e5b6b678cd28-ex2', 'df7d9651-253a-480e-af13-e5b6b678cd28', 'closet', 'The audit unearthed liabilities the firm had kept in the closet for years.', '审计揭出了该公司多年来一直隐瞒的负债。'),
  ('0c0a1f42-38fd-4dc5-93e0-867c4b64021e-ex1', '0c0a1f42-38fd-4dc5-93e0-867c4b64021e', 'suburban', 'They moved to a suburban neighborhood.', '他们搬到了郊区社区。'),
  ('0c0a1f42-38fd-4dc5-93e0-867c4b64021e-ex2', '0c0a1f42-38fd-4dc5-93e0-867c4b64021e', 'suburban', 'Suburban sprawl outpaced the provision of public transit infrastructure.', '郊区的无序蔓延超过了公共交通基础设施的供给。'),
  ('fa7b8ca1-8302-40f1-b4e3-e4e6cc1cc26a-ex1', 'fa7b8ca1-8302-40f1-b4e3-e4e6cc1cc26a', 'greet', 'She greeted us with a smile.', '她微笑着迎接我们。'),
  ('fa7b8ca1-8302-40f1-b4e3-e4e6cc1cc26a-ex2', 'fa7b8ca1-8302-40f1-b4e3-e4e6cc1cc26a', 'greet', 'The proposal was greeted with skepticism that subsequent events vindicated.', '该提案遭遇的怀疑后来被事实证明是有道理的。'),
  ('152c91ca-ab5b-46b7-9a7a-4858ec2f0372-ex1', '152c91ca-ab5b-46b7-9a7a-4858ec2f0372', 'interior', 'The car''s interior is very clean.', '这辆车的内饰很干净。'),
  ('152c91ca-ab5b-46b7-9a7a-4858ec2f0372-ex2', '152c91ca-ab5b-46b7-9a7a-4858ec2f0372', 'interior', 'The ministry of the interior oversees the conduct of national elections.', '内政部负责监督全国选举的进行。'),
  ('2fae9e8f-e708-49b5-b07a-4ddb003f7cd7-ex1', '2fae9e8f-e708-49b5-b07a-4ddb003f7cd7', 'corridor', 'The office is at the end of the corridor.', '办公室在走廊尽头。'),
  ('2fae9e8f-e708-49b5-b07a-4ddb003f7cd7-ex2', '2fae9e8f-e708-49b5-b07a-4ddb003f7cd7', 'corridor', 'Investment surged across the industrial corridor following trade liberalization.', '贸易自由化之后，工业走廊的投资激增。'),
  ('e94d19cf-291f-4661-a0c6-b978410236e8-ex1', 'e94d19cf-291f-4661-a0c6-b978410236e8', 'retail', 'She works in retail.', '她从事零售业。'),
  ('e94d19cf-291f-4661-a0c6-b978410236e8-ex2', 'e94d19cf-291f-4661-a0c6-b978410236e8', 'retail', 'Retail investors bore disproportionate losses from the misrepresented offerings.', '散户投资者在这些虚假陈述的发行中蒙受了不成比例的损失。'),
  ('4966631e-c7f9-41e4-924b-4148974690d3-ex1', '4966631e-c7f9-41e4-924b-4148974690d3', 'pitcher', 'Fill the pitcher with water.', '把水罐装满水。'),
  ('4966631e-c7f9-41e4-924b-4148974690d3-ex2', '4966631e-c7f9-41e4-924b-4148974690d3', 'pitcher', 'The star pitcher''s contract dispute reached binding arbitration.', '这位明星投手的合同纠纷进入了有约束力的仲裁。'),
  ('c0029a6a-80eb-4ea8-9056-f95f939e1697-ex1', 'c0029a6a-80eb-4ea8-9056-f95f939e1697', 'march', 'The band will march in the parade.', '乐队将在游行中行进。'),
  ('c0029a6a-80eb-4ea8-9056-f95f939e1697-ex2', 'c0029a6a-80eb-4ea8-9056-f95f939e1697', 'march', 'Thousands joined the march demanding comprehensive electoral reform.', '数千人加入游行，要求进行全面的选举改革。'),
  ('41b1ffed-fbf4-4cba-b7ee-1d4574f78572-ex1', '41b1ffed-fbf4-4cba-b7ee-1d4574f78572', 'snake', 'A snake slithered across the path.', '一条蛇从小路上滑过。'),
  ('41b1ffed-fbf4-4cba-b7ee-1d4574f78572-ex2', '41b1ffed-fbf4-4cba-b7ee-1d4574f78572', 'snake', 'The road snakes through valleys before reaching the remote settlement.', '这条路蜿蜒穿过山谷，最终通往那个偏远的聚居地。'),
  ('684ec053-5a0d-4e00-97ab-092aec279010-ex1', '684ec053-5a0d-4e00-97ab-092aec279010', 'excuse', 'That is no excuse for being rude.', '那不是无礼的借口。'),
  ('684ec053-5a0d-4e00-97ab-092aec279010-ex2', '684ec053-5a0d-4e00-97ab-092aec279010', 'excuse', 'Ignorance of the regulation furnishes no excuse for the violations.', '对法规的不知情不能成为违规行为的借口。'),
  ('83031ec5-1247-4ab3-b030-5aefc08eacad-ex1', '83031ec5-1247-4ab3-b030-5aefc08eacad', 'weakness', 'Everyone has their weaknesses.', '每个人都有自己的弱点。'),
  ('83031ec5-1247-4ab3-b030-5aefc08eacad-ex2', '83031ec5-1247-4ab3-b030-5aefc08eacad', 'weakness', 'The crisis exposed structural weaknesses the regulator had long ignored.', '这场危机暴露了监管机构长期忽视的结构性弱点。'),
  ('79145714-cc10-494c-873d-e71b837db316-ex1', '79145714-cc10-494c-873d-e71b837db316', 'pig', 'The farmer raises pigs.', '这位农民养猪。'),
  ('79145714-cc10-494c-873d-e71b837db316-ex2', '79145714-cc10-494c-873d-e71b837db316', 'pig', 'The disease prompted a precautionary cull of every pig on the affected farms.', '疫情促使对受影响农场的每头猪实施预防性扑杀。'),
  ('1f356f7b-6a50-4216-9543-07792a48b5d5-ex1', '1f356f7b-6a50-4216-9543-07792a48b5d5', 'classical', 'She enjoys classical music.', '她喜欢古典音乐。'),
