  ('3f0d2132-5574-4106-9e49-7ce0a4bbaa26-ex1', '3f0d2132-5574-4106-9e49-7ce0a4bbaa26', 'convict', 'The jury voted to convict him.', '陪审团投票判他有罪。'),
