  ('804eaa52-e531-4454-987a-592df015f559-ex1', '804eaa52-e531-4454-987a-592df015f559', 'ballot', 'She cast her ballot in the morning.', '她上午投了票。'),
  ('804eaa52-e531-4454-987a-592df015f559-ex2', '804eaa52-e531-4454-987a-592df015f559', 'ballot', 'Each provisional ballot is counted only after eligibility is verified.', '每张临时选票只有在资格核实后才计入。'),
