  ('43f5e1d2-28ae-4c34-a55d-823a55517bcc-ex1', '43f5e1d2-28ae-4c34-a55d-823a55517bcc', 'wilderness', 'They hiked through the wilderness.', '他们徒步穿越荒野。'),
  ('43f5e1d2-28ae-4c34-a55d-823a55517bcc-ex2', '43f5e1d2-28ae-4c34-a55d-823a55517bcc', 'wilderness', 'The designation preserves the wilderness from development in perpetuity.', '这项划定使这片荒野永久免遭开发。'),
  ('67352b75-ffb4-4f11-8a70-5cb4f04a673b-ex1', '67352b75-ffb4-4f11-8a70-5cb4f04a673b', 'endless', 'The journey felt endless.', '这段旅程似乎没有尽头。'),
