  ('aa0faec3-baec-4dae-b828-22782c832d0d-ex2', 'aa0faec3-baec-4dae-b828-22782c832d0d', 'uncertainty', 'Persistent legal uncertainty deterred investment the reform was meant to attract.', '持续的法律不确定性吓退了改革本欲吸引的投资。'),
  ('a1d380b3-f11e-440b-a02d-a2123435bf3a-ex1', 'a1d380b3-f11e-440b-a02d-a2123435bf3a', 'chaos', 'The room was in complete chaos.', '房间里一片混乱。'),
