  ('e7004ad5-779e-47a0-ade2-a892555e90c8-ex2', 'e7004ad5-779e-47a0-ade2-a892555e90c8', 'format', 'The disclosure must appear in a format intelligible to the ordinary reader.', '披露必须以普通读者能够理解的格式呈现。'),
  ('7a2abdcb-416a-4898-8083-2b5911442ebb-ex1', '7a2abdcb-416a-4898-8083-2b5911442ebb', 'trait', 'Honesty is an admirable trait.', '诚实是一种可贵的品质。'),
  ('7a2abdcb-416a-4898-8083-2b5911442ebb-ex2', '7a2abdcb-416a-4898-8083-2b5911442ebb', 'trait', 'Opacity is the defining trait of the structures under investigation.', '不透明是受调查架构的根本特征。'),
  ('8197bc58-f706-4608-a58e-fe4ed3bac509-ex1', '8197bc58-f706-4608-a58e-fe4ed3bac509', 'currency', 'What currency do they use there?', '他们那里用什么货币？'),
  ('8197bc58-f706-4608-a58e-fe4ed3bac509-ex2', '8197bc58-f706-4608-a58e-fe4ed3bac509', 'currency', 'The currency depreciated sharply as confidence in the peg deteriorated.', '随着对汇率挂钩制度信心的恶化，本币大幅贬值。'),
  ('c55218ae-1985-44ff-a1ba-c85c66a9ad7a-ex1', 'c55218ae-1985-44ff-a1ba-c85c66a9ad7a', 'turkey', 'We roast a turkey for the holiday.', '我们过节烤火鸡。'),
  ('c55218ae-1985-44ff-a1ba-c85c66a9ad7a-ex2', 'c55218ae-1985-44ff-a1ba-c85c66a9ad7a', 'turkey', 'Investors abandoned the venture, dismissing it as a turkey from the outset.', '投资者放弃了这个项目，认为它从一开始就是个失败之作。'),
  ('dffa52e0-3b35-4c3a-a1f6-4050ff388a56-ex1', 'dffa52e0-3b35-4c3a-a1f6-4050ff388a56', 'reserve', 'I would like to reserve a table for two.', '我想订一张两人桌。'),
  ('dffa52e0-3b35-4c3a-a1f6-4050ff388a56-ex2', 'dffa52e0-3b35-4c3a-a1f6-4050ff388a56', 'reserve', 'The central bank''s reserves dwindled as it defended the currency peg.', '央行在捍卫汇率挂钩时储备不断减少。'),
  ('e59ce111-56a0-4c5c-aec5-096fe32267ba-ex1', 'e59ce111-56a0-4c5c-aec5-096fe32267ba', 'beam', 'A beam of light entered the room.', '一束光照进了房间。'),
  ('e59ce111-56a0-4c5c-aec5-096fe32267ba-ex2', 'e59ce111-56a0-4c5c-aec5-096fe32267ba', 'beam', 'The corroded support beam failed under loads well within design limits.', '受腐蚀的支撑梁在远未超出设计限度的载荷下断裂。'),
  ('c3c2d953-ab79-495c-b35a-0ad66914d7eb-ex1', 'c3c2d953-ab79-495c-b35a-0ad66914d7eb', 'astronomer', 'The astronomer studied distant stars.', '天文学家研究遥远的恒星。'),
  ('c3c2d953-ab79-495c-b35a-0ad66914d7eb-ex2', 'c3c2d953-ab79-495c-b35a-0ad66914d7eb', 'astronomer', 'Astronomers documented the collapse of a massive star into a dense remnant.', '天文学家记录了一颗大质量恒星坍缩为致密残骸的过程。'),
  ('b8ae1717-e97b-4e56-a78b-e1658940263f-ex1', 'b8ae1717-e97b-4e56-a78b-e1658940263f', 'corruption', 'The country is fighting corruption.', '该国正在打击腐败。'),
  ('b8ae1717-e97b-4e56-a78b-e1658940263f-ex2', 'b8ae1717-e97b-4e56-a78b-e1658940263f', 'corruption', 'The convention obliges states to criminalize the corruption of public officials.', '该公约要求各国将贿赂公职人员的行为定为犯罪。'),
  ('5185a3d0-b2c7-4e83-b467-dc30e176799d-ex1', '5185a3d0-b2c7-4e83-b467-dc30e176799d', 'contractor', 'The contractor finished the work early.', '承包商提前完成了工程。'),
  ('5185a3d0-b2c7-4e83-b467-dc30e176799d-ex2', '5185a3d0-b2c7-4e83-b467-dc30e176799d', 'contractor', 'The contractor bears liability for defects inherent in the approved design.', '承包商对获批设计中固有的缺陷承担责任。'),
  ('da481289-a22f-408f-9a2f-3e2a3d5e6626-ex1', 'da481289-a22f-408f-9a2f-3e2a3d5e6626', 'apologize', 'I apologize for being late.', '我为迟到道歉。'),
  ('da481289-a22f-408f-9a2f-3e2a3d5e6626-ex2', 'da481289-a22f-408f-9a2f-3e2a3d5e6626', 'apologize', 'The minister declined to apologize for failures occurring under his stewardship.', '部长拒绝为其任内发生的失误道歉。'),
