  ('0e030470-ba70-4473-9c50-90245d40d3b0-ex2', '0e030470-ba70-4473-9c50-90245d40d3b0', 'doctrine', 'The ruling overturns a doctrine that had stood for half a century.', '这一裁决推翻了沿用半个世纪的法律原则。'),
  ('1a7921bf-64c0-4a3d-be66-978c0dd2c96b-ex1', '1a7921bf-64c0-4a3d-be66-978c0dd2c96b', 'genuine', 'She showed genuine concern.', '她表现出真诚的关心。'),
