  ('3e278bdc-3e2c-43fa-adee-1a04308f55cb-ex1', '3e278bdc-3e2c-43fa-adee-1a04308f55cb', 'fork', 'Use a fork to eat the cake.', '用叉子吃蛋糕。'),
