  ('bbeb6933-fba9-4cce-83fe-af94d18b4868-ex2', 'bbeb6933-fba9-4cce-83fe-af94d18b4868', 'frozen', 'The frozen assets may be released only under judicially supervised conditions.', '被冻结的资产只能在司法监督的条件下解冻。'),
  ('e4e82401-026e-43fa-96af-01539f2ad461-ex1', 'e4e82401-026e-43fa-96af-01539f2ad461', 'spouse', 'You can bring your spouse to the dinner.', '晚宴你可以带配偶来。'),
  ('e4e82401-026e-43fa-96af-01539f2ad461-ex2', 'e4e82401-026e-43fa-96af-01539f2ad461', 'spouse', 'The pension provisions entitle a surviving spouse to accrued benefits.', '养老金条款规定在世配偶有权获得累积的待遇。'),
  ('bced53e9-d9a0-4bf3-aea3-a11a17c5afeb-ex1', 'bced53e9-d9a0-4bf3-aea3-a11a17c5afeb', 'fluid', 'Drink plenty of fluids when sick.', '生病时要多喝水。'),
  ('bced53e9-d9a0-4bf3-aea3-a11a17c5afeb-ex2', 'bced53e9-d9a0-4bf3-aea3-a11a17c5afeb', 'fluid', 'The situation remained fluid as negotiating positions shifted hourly.', '由于谈判立场每时每刻都在变化，局势依然不明朗。'),
  ('5cd53552-90b5-4a5e-85e1-9fb37c0d7e49-ex1', '5cd53552-90b5-4a5e-85e1-9fb37c0d7e49', 'pension', 'He receives a monthly pension.', '他每月领取养老金。'),
  ('5cd53552-90b5-4a5e-85e1-9fb37c0d7e49-ex2', '5cd53552-90b5-4a5e-85e1-9fb37c0d7e49', 'pension', 'The pension scheme''s unfunded liabilities dwarf the municipal budget.', '该养老金计划的未拨备负债远超市政预算。'),
  ('4df1d326-ec2c-4673-8efa-d26f01b199bb-ex1', '4df1d326-ec2c-4673-8efa-d26f01b199bb', 'resume', 'Please send me your resume.', '请把简历发给我。'),
  ('4df1d326-ec2c-4673-8efa-d26f01b199bb-ex2', '4df1d326-ec2c-4673-8efa-d26f01b199bb', 'resume', 'The parties agreed to resume negotiations despite the persistent differences.', '尽管分歧依旧，双方同意恢复谈判。'),
  ('f8153137-6811-463f-932e-90b934a7b2b9-ex1', 'f8153137-6811-463f-932e-90b934a7b2b9', 'theoretical', 'The course is mostly theoretical.', '这门课主要是理论性的。'),
  ('f8153137-6811-463f-932e-90b934a7b2b9-ex2', 'f8153137-6811-463f-932e-90b934a7b2b9', 'theoretical', 'The risk, though theoretical when raised, materialized within the year.', '这一风险提出时虽属理论上的，却在一年内成为现实。'),
  ('677c571a-b2ef-404f-abc0-34f5ba648a7c-ex1', '677c571a-b2ef-404f-abc0-34f5ba648a7c', 'sodium', 'Too much sodium is bad for you.', '钠摄入过多对身体不好。'),
  ('677c571a-b2ef-404f-abc0-34f5ba648a7c-ex2', '677c571a-b2ef-404f-abc0-34f5ba648a7c', 'sodium', 'The labeling reforms mandate disclosure of sodium content per serving.', '标签改革要求披露每份食品的钠含量。'),
  ('788eb1dd-4e42-4702-b6e0-01d68d9ea2d7-ex1', '788eb1dd-4e42-4702-b6e0-01d68d9ea2d7', 'promotion', 'She got a promotion at work.', '她在工作上得到了晋升。'),
  ('788eb1dd-4e42-4702-b6e0-01d68d9ea2d7-ex2', '788eb1dd-4e42-4702-b6e0-01d68d9ea2d7', 'promotion', 'Endorsement rules require disclosure of paid promotion to consumers.', '代言规则要求向消费者披露付费推广。'),
  ('02a490aa-35b1-465c-90e8-d3d9c919c62e-ex1', '02a490aa-35b1-465c-90e8-d3d9c919c62e', 'delicate', 'The vase is very delicate.', '这个花瓶很易碎。'),
  ('02a490aa-35b1-465c-90e8-d3d9c919c62e-ex2', '02a490aa-35b1-465c-90e8-d3d9c919c62e', 'delicate', 'The negotiator occupies a delicate position between irreconcilable demands.', '调解人处在无法调和的诉求之间，立场微妙。'),
  ('88c5d544-13dd-40fc-ad83-30e3b8a42333-ex1', '88c5d544-13dd-40fc-ad83-30e3b8a42333', 'forehead', 'She wiped her forehead with a tissue.', '她用纸巾擦了擦额头。'),
  ('88c5d544-13dd-40fc-ad83-30e3b8a42333-ex2', '88c5d544-13dd-40fc-ad83-30e3b8a42333', 'forehead', 'He frowned, the lines on his forehead betraying mounting concern.', '他皱起眉头，额上的纹路透露出日益加深的忧虑。'),
  ('3e6cf741-95ff-43ca-b153-c32865e2b9bc-ex1', '3e6cf741-95ff-43ca-b153-c32865e2b9bc', 'rebuild', 'They plan to rebuild the old bridge.', '他们计划重建那座老桥。'),
  ('3e6cf741-95ff-43ca-b153-c32865e2b9bc-ex2', '3e6cf741-95ff-43ca-b153-c32865e2b9bc', 'rebuild', 'The accord seeks to rebuild institutional trust between estranged parties.', '该协议旨在重建关系疏远的各方之间的制度性信任。'),
  ('1d9716ff-86d2-4c39-aaee-052469d2eb7b-ex1', '1d9716ff-86d2-4c39-aaee-052469d2eb7b', 'bounce', 'The ball bounced off the wall.', '球从墙上弹了回来。'),
  ('1d9716ff-86d2-4c39-aaee-052469d2eb7b-ex2', '1d9716ff-86d2-4c39-aaee-052469d2eb7b', 'bounce', 'The currency bounced briefly before resuming its sustained decline.', '本币短暂反弹后重拾持续跌势。'),
  ('549a2c01-2cd4-4b34-acad-08e49bc804e4-ex1', '549a2c01-2cd4-4b34-acad-08e49bc804e4', 'electrical', 'There is an electrical fault in the house.', '房子里有电路故障。'),
  ('549a2c01-2cd4-4b34-acad-08e49bc804e4-ex2', '549a2c01-2cd4-4b34-acad-08e49bc804e4', 'electrical', 'The inquiry traced the fire to an electrical fault the inspections had missed.', '调查将火灾追溯到检查时遗漏的一处电路故障。'),
  ('3eb3037a-5d79-4ac7-9c84-954af9233657-ex1', '3eb3037a-5d79-4ac7-9c84-954af9233657', 'hook', 'Hang your coat on the hook.', '把外套挂在挂钩上。'),
  ('3eb3037a-5d79-4ac7-9c84-954af9233657-ex2', '3eb3037a-5d79-4ac7-9c84-954af9233657', 'hook', 'The indemnity clause left the guarantor on the hook for consequential losses.', '赔偿条款使担保人需为间接损失承担责任。'),
  ('8960cb30-e2d3-4035-ae9e-5c440e9f88c7-ex1', '8960cb30-e2d3-4035-ae9e-5c440e9f88c7', 'detective', 'The detective solved the case.', '侦探破了案。'),
  ('8960cb30-e2d3-4035-ae9e-5c440e9f88c7-ex2', '8960cb30-e2d3-4035-ae9e-5c440e9f88c7', 'detective', 'The detective''s notes, withheld for years, surfaced during discovery.', '侦探多年来扣留的笔记在证据开示期间浮出水面。'),
  ('43859a8b-7c5a-4697-8ad2-e381e750124a-ex1', '43859a8b-7c5a-4697-8ad2-e381e750124a', 'traveler', 'The traveler asked for directions.', '旅行者问路。'),
  ('43859a8b-7c5a-4697-8ad2-e381e750124a-ex2', '43859a8b-7c5a-4697-8ad2-e381e750124a', 'traveler', 'The advisory restricts travelers to regions unaffected by the outbreak.', '该公告限制旅客前往未受疫情影响的地区。'),
  ('c061ae6d-1af8-42e3-9b9f-1d69cbc7d373-ex1', 'c061ae6d-1af8-42e3-9b9f-1d69cbc7d373', 'click', 'Click the button to continue.', '点击按钮继续。'),
  ('c061ae6d-1af8-42e3-9b9f-1d69cbc7d373-ex2', 'c061ae6d-1af8-42e3-9b9f-1d69cbc7d373', 'click', 'A single click may suffice to form a binding contract under the commerce act.', '根据商务法，仅点击一下即可能构成有约束力的合同。'),
  ('5112b498-2384-42cd-95ff-5c102ec060b7-ex1', '5112b498-2384-42cd-95ff-5c102ec060b7', 'compensation', 'She received compensation for the damage.', '她因损失获得了赔偿。'),
  ('5112b498-2384-42cd-95ff-5c102ec060b7-ex2', '5112b498-2384-42cd-95ff-5c102ec060b7', 'compensation', 'The settlement requires compensation commensurate with the documented loss.', '和解协议要求支付与记录在案损失相称的赔偿。'),
  ('f11ecd4f-1adb-44ac-a9e3-d746422e64b4-ex1', 'f11ecd4f-1adb-44ac-a9e3-d746422e64b4', 'exit', 'The emergency exit is on the left.', '紧急出口在左边。'),
  ('f11ecd4f-1adb-44ac-a9e3-d746422e64b4-ex2', 'f11ecd4f-1adb-44ac-a9e3-d746422e64b4', 'exit', 'Member states prepared contingency plans for a disorderly market exit.', '成员国为无序退出市场的情形准备了应急预案。'),
  ('74e82d38-1588-411a-b633-abfa781acf15-ex1', '74e82d38-1588-411a-b633-abfa781acf15', 'attraction', 'The castle is a popular attraction.', '这座城堡是热门景点。'),
  ('74e82d38-1588-411a-b633-abfa781acf15-ex2', '74e82d38-1588-411a-b633-abfa781acf15', 'attraction', 'The subsidy''s attraction faded once its conditions became burdensome.', '一旦补贴条件变得繁重，其吸引力便随之消退。'),
  ('a370a3d0-059b-438b-a16c-b849a50ff29a-ex1', 'a370a3d0-059b-438b-a16c-b849a50ff29a', 'dedicate', 'She dedicated the book to her mother.', '她把这本书献给了母亲。'),
  ('a370a3d0-059b-438b-a16c-b849a50ff29a-ex2', 'a370a3d0-059b-438b-a16c-b849a50ff29a', 'dedicate', 'The institute dedicates substantial resources to research insulated from pressure.', '该研究所投入大量资源开展不受压力影响的研究。'),
  ('d23677c4-8f9b-4314-befc-f8fd5696d7da-ex1', 'd23677c4-8f9b-4314-befc-f8fd5696d7da', 'altogether', 'There were ten of us altogether.', '我们一共有十个人。'),
  ('d23677c4-8f9b-4314-befc-f8fd5696d7da-ex2', 'd23677c4-8f9b-4314-befc-f8fd5696d7da', 'altogether', 'The exemption was abolished altogether by the consolidating statute.', '该豁免被整合法规彻底废除。'),
  ('e02bdbc1-2605-4dba-8a44-4148c6291d37-ex1', 'e02bdbc1-2605-4dba-8a44-4148c6291d37', 'pickup', 'He drives an old pickup truck.', '他开着一辆旧皮卡。'),
  ('e02bdbc1-2605-4dba-8a44-4148c6291d37-ex2', 'e02bdbc1-2605-4dba-8a44-4148c6291d37', 'pickup', 'The pickup in demand strained supply chains already operating at capacity.', '需求的回升给本已满负荷运转的供应链带来了压力。'),
