  ('25870a0e-6169-42ec-9054-56ad4e93390c-ex2', '25870a0e-6169-42ec-9054-56ad4e93390c', 'engagement', 'The auditor''s prior engagement with the client compromised its independence.', '审计师此前与客户的业务往来损害了其独立性。'),
  ('0a925380-d54b-49de-9582-c4e0c492a634-ex1', '0a925380-d54b-49de-9582-c4e0c492a634', 'ankle', 'She twisted her ankle on the stairs.', '她在楼梯上扭伤了脚踝。'),
  ('0a925380-d54b-49de-9582-c4e0c492a634-ex2', '0a925380-d54b-49de-9582-c4e0c492a634', 'ankle', 'The injury to his ankle ended a career at its athletic peak.', '脚踝的伤病使他在运动巅峰期结束了职业生涯。'),
  ('36037823-caa4-4a24-8dce-0abba7b007af-ex1', '36037823-caa4-4a24-8dce-0abba7b007af', 'transaction', 'The transaction was completed online.', '这笔交易在线上完成。'),
  ('36037823-caa4-4a24-8dce-0abba7b007af-ex2', '36037823-caa4-4a24-8dce-0abba7b007af', 'transaction', 'Each transaction above the threshold triggers a mandatory reporting obligation.', '每笔超过门槛的交易都会触发强制申报义务。'),
  ('f91bd77f-23c7-4dbb-86a9-0bdd0f4cbd5c-ex1', 'f91bd77f-23c7-4dbb-86a9-0bdd0f4cbd5c', 'rescue', 'The firefighters rescued the cat.', '消防员救出了那只猫。'),
