  ('c95faf32-1cf1-4e2b-9f6d-6040e38e6385-ex1', 'c95faf32-1cf1-4e2b-9f6d-6040e38e6385', 'noon', 'Let''s meet at noon.', '我们中午见。'),
  ('c95faf32-1cf1-4e2b-9f6d-6040e38e6385-ex2', 'c95faf32-1cf1-4e2b-9f6d-6040e38e6385', 'noon', 'Trading was suspended before noon amid an unprecedented surge in volatility.', '在波动空前激增之际，交易于中午前暂停。'),
  ('7c67638c-1214-4c3f-af3f-a87d00763c22-ex1', '7c67638c-1214-4c3f-af3f-a87d00763c22', 'amid', 'She stayed calm amid the chaos.', '在混乱中她保持镇定。'),
  ('7c67638c-1214-4c3f-af3f-a87d00763c22-ex2', '7c67638c-1214-4c3f-af3f-a87d00763c22', 'amid', 'The reforms were enacted amid mounting public distrust of institutions.', '这些改革是在公众对体制机构日益不信任的背景下颁布的。'),
  ('a64040f6-4834-4896-a906-1a5908e877d6-ex1', 'a64040f6-4834-4896-a906-1a5908e877d6', 'identical', 'The two bags look identical.', '这两个包看起来一模一样。'),
  ('a64040f6-4834-4896-a906-1a5908e877d6-ex2', 'a64040f6-4834-4896-a906-1a5908e877d6', 'identical', 'The claims arise from substantially identical facts and were consolidated.', '这些索赔基于实质相同的事实，因此被合并审理。'),
  ('71eef57c-df51-46e3-98d1-fb030192f2f6-ex1', '71eef57c-df51-46e3-98d1-fb030192f2f6', 'precise', 'Give me the precise time.', '告诉我确切的时间。'),
  ('71eef57c-df51-46e3-98d1-fb030192f2f6-ex2', '71eef57c-df51-46e3-98d1-fb030192f2f6', 'precise', 'The clause was drafted with precise care to foreclose the contested reading.', '该条款经过精心起草，以排除有争议的解读。'),
  ('0c688a9d-6712-48bc-9f09-dc58dc326459-ex1', '0c688a9d-6712-48bc-9f09-dc58dc326459', 'anxious', 'She was anxious about the result.', '她为结果而焦虑。'),
  ('0c688a9d-6712-48bc-9f09-dc58dc326459-ex2', '0c688a9d-6712-48bc-9f09-dc58dc326459', 'anxious', 'Markets grew anxious as the central bank repeatedly deferred its guidance.', '随着央行一再推迟指引，市场愈发焦虑。'),
  ('301ee23f-90ac-4de6-8175-0c6f2a8ea4d0-ex1', '301ee23f-90ac-4de6-8175-0c6f2a8ea4d0', 'structural', 'The bridge has a structural problem.', '这座桥有结构性问题。'),
  ('301ee23f-90ac-4de6-8175-0c6f2a8ea4d0-ex2', '301ee23f-90ac-4de6-8175-0c6f2a8ea4d0', 'structural', 'The crisis exposed structural imbalances prosperity had long concealed.', '这场危机暴露了长期被繁荣掩盖的结构性失衡。'),
  ('eec71ece-c090-4711-a5e3-5e9daabbbe53-ex1', 'eec71ece-c090-4711-a5e3-5e9daabbbe53', 'residential', 'This is a quiet residential area.', '这是一个安静的住宅区。'),
  ('eec71ece-c090-4711-a5e3-5e9daabbbe53-ex2', 'eec71ece-c090-4711-a5e3-5e9daabbbe53', 'residential', 'The rezoning converted industrial land to certified residential use.', '重新规划将工业用地转为经认证的住宅用途。'),
  ('8a59c93b-692d-4cae-b282-824150324840-ex1', '8a59c93b-692d-4cae-b282-824150324840', 'diagnose', 'The doctor diagnosed the illness.', '医生诊断出了病症。'),
  ('8a59c93b-692d-4cae-b282-824150324840-ex2', '8a59c93b-692d-4cae-b282-824150324840', 'diagnose', 'Imaging enables doctors to diagnose the disease at substantially earlier stages.', '影像技术使医生能在更早的阶段诊断出该疾病。'),
  ('63c71c79-1053-47b0-beaf-3f7a17d58255-ex1', '63c71c79-1053-47b0-beaf-3f7a17d58255', 'carbohydrate', 'Bread is high in carbohydrates.', '面包碳水化合物含量高。'),
  ('63c71c79-1053-47b0-beaf-3f7a17d58255-ex2', '63c71c79-1053-47b0-beaf-3f7a17d58255', 'carbohydrate', 'The labeling rules govern carbohydrate content claims on packaged foods.', '标签规则规范包装食品的碳水化合物含量声明。'),
  ('5fb4890c-7fbe-4337-bf0e-860670eedf2b-ex1', '5fb4890c-7fbe-4337-bf0e-860670eedf2b', 'liberty', 'They fought for liberty.', '他们为自由而战。'),
  ('5fb4890c-7fbe-4337-bf0e-860670eedf2b-ex2', '5fb4890c-7fbe-4337-bf0e-860670eedf2b', 'liberty', 'The court weighed the danger of flight against the presumption of liberty.', '法院在潜逃风险与自由推定之间进行了权衡。'),
  ('9c9eca18-1928-4cc1-a1d9-1c1051318c88-ex1', '9c9eca18-1928-4cc1-a1d9-1c1051318c88', 'poster', 'She hung a movie poster on the wall.', '她在墙上贴了一张电影海报。'),
  ('9c9eca18-1928-4cc1-a1d9-1c1051318c88-ex2', '9c9eca18-1928-4cc1-a1d9-1c1051318c88', 'poster', 'The advertising rules require political posters to disclose their sponsors.', '广告规则要求政治海报披露其出资方。'),
  ('6c02de9a-24fb-4b3a-a007-d87aa2195bdf-ex1', '6c02de9a-24fb-4b3a-a007-d87aa2195bdf', 'theology', 'He studied theology at university.', '他在大学学习神学。'),
  ('6c02de9a-24fb-4b3a-a007-d87aa2195bdf-ex2', '6c02de9a-24fb-4b3a-a007-d87aa2195bdf', 'theology', 'The dispute over the endowment turned on a point of doctrinal theology.', '围绕这笔捐赠的争议归结于一个神学教义问题。'),
  ('e82d49bc-dc3d-4404-8ca5-101a5640cc55-ex1', 'e82d49bc-dc3d-4404-8ca5-101a5640cc55', 'nonprofit', 'She works for a nonprofit organization.', '她在一家非营利组织工作。'),
  ('e82d49bc-dc3d-4404-8ca5-101a5640cc55-ex2', 'e82d49bc-dc3d-4404-8ca5-101a5640cc55', 'nonprofit', 'The nonprofit''s governance was overhauled after findings of impropriety.', '在不当行为被查实后，这家非营利组织的治理结构得到了彻底改革。'),
  ('b4fd3b37-4ad9-4df8-8f41-2567e94a9034-ex1', 'b4fd3b37-4ad9-4df8-8f41-2567e94a9034', 'crawl', 'The baby learned to crawl.', '宝宝学会了爬。'),
  ('b4fd3b37-4ad9-4df8-8f41-2567e94a9034-ex2', 'b4fd3b37-4ad9-4df8-8f41-2567e94a9034', 'crawl', 'The litigation crawled across two decades and three jurisdictions.', '这场诉讼历时二十年，横跨三个司法管辖区，进展缓慢。'),
  ('cbd25159-3be9-46ff-9884-309616841af3-ex1', 'cbd25159-3be9-46ff-9884-309616841af3', 'oxygen', 'Fish need oxygen in the water.', '鱼需要水中的氧气。'),
  ('cbd25159-3be9-46ff-9884-309616841af3-ex2', 'cbd25159-3be9-46ff-9884-309616841af3', 'oxygen', 'Cheap credit was the oxygen that sustained the unsustainable leverage.', '廉价信贷是维系不可持续杠杆的氧气。'),
  ('c6cad94e-3f8f-4c77-bb09-5d99d4595c71-ex1', 'c6cad94e-3f8f-4c77-bb09-5d99d4595c71', 'handsome', 'He is a tall, handsome man.', '他是个高大英俊的男人。'),
  ('c6cad94e-3f8f-4c77-bb09-5d99d4595c71-ex2', 'c6cad94e-3f8f-4c77-bb09-5d99d4595c71', 'handsome', 'The fund posted handsome returns through risks it never disclosed.', '该基金凭借从未披露的风险取得了可观的回报。'),
  ('bc549db0-b6c8-4928-a786-41647ba3d489-ex1', 'bc549db0-b6c8-4928-a786-41647ba3d489', 'sum', 'The sum of two and three is five.', '二加三的和是五。'),
  ('bc549db0-b6c8-4928-a786-41647ba3d489-ex2', 'bc549db0-b6c8-4928-a786-41647ba3d489', 'sum', 'The settlement required repayment of a substantial sum together with interest.', '和解协议要求连同利息偿还一笔可观的款项。'),
  ('db347963-b8cf-458d-834e-1f704b606812-ex1', 'db347963-b8cf-458d-834e-1f704b606812', 'provided', 'You can go, provided you finish first.', '只要你先做完，就可以走。'),
  ('db347963-b8cf-458d-834e-1f704b606812-ex2', 'db347963-b8cf-458d-834e-1f704b606812', 'provided', 'The waiver remains valid provided the conditions precedent are satisfied.', '只要先决条件得到满足，该豁免即持续有效。'),
  ('a345aacc-3643-4738-a7f2-ba9168ded515-ex1', 'a345aacc-3643-4738-a7f2-ba9168ded515', 'businessman', 'The businessman opened a new store.', '这位商人开了一家新店。'),
  ('a345aacc-3643-4738-a7f2-ba9168ded515-ex2', 'a345aacc-3643-4738-a7f2-ba9168ded515', 'businessman', 'The prominent businessman was indicted for orchestrating the fraud.', '这位知名商人因策划这起欺诈而被起诉。'),
  ('e95bd71b-18a9-4032-aa66-a5d9793025f0-ex1', 'e95bd71b-18a9-4032-aa66-a5d9793025f0', 'promising', 'She is a promising young writer.', '她是一位前途无量的年轻作家。'),
  ('e95bd71b-18a9-4032-aa66-a5d9793025f0-ex2', 'e95bd71b-18a9-4032-aa66-a5d9793025f0', 'promising', 'The promising venture collapsed once the regulatory risk materialized.', '监管风险一旦成为现实，这个前景看好的项目便垮掉了。'),
  ('d28f950d-b5db-4334-b84d-b427a70c0c5a-ex1', 'd28f950d-b5db-4334-b84d-b427a70c0c5a', 'conscious', 'He was still conscious after the fall.', '摔倒后他仍然清醒。'),
  ('d28f950d-b5db-4334-b84d-b427a70c0c5a-ex2', 'd28f950d-b5db-4334-b84d-b427a70c0c5a', 'conscious', 'The directors were fully conscious of the risks they elected to conceal.', '董事们对其选择隐瞒的风险完全心知肚明。'),
  ('7aa003ad-e371-4db5-8313-e9175c718184-ex1', '7aa003ad-e371-4db5-8313-e9175c718184', 'determination', 'Her determination impressed everyone.', '她的决心给所有人留下了深刻印象。'),
  ('7aa003ad-e371-4db5-8313-e9175c718184-ex2', '7aa003ad-e371-4db5-8313-e9175c718184', 'determination', 'The tribunal''s determination of fact is binding absent manifest error.', '除非存在明显错误，法庭的事实认定具有约束力。'),
  ('9eac0dc1-cfde-48dd-ba40-f50d8b9075ea-ex1', '9eac0dc1-cfde-48dd-ba40-f50d8b9075ea', 'donor', 'The blood donor saved a life.', '献血者挽救了一条生命。'),
  ('9eac0dc1-cfde-48dd-ba40-f50d8b9075ea-ex2', '9eac0dc1-cfde-48dd-ba40-f50d8b9075ea', 'donor', 'The sponsor required donors to disclose contributions above the threshold.', '发起方要求捐赠者披露超过门槛的捐款。'),
  ('684a67c4-1186-4d0c-a261-03efe28af195-ex1', '684a67c4-1186-4d0c-a261-03efe28af195', 'hers', 'That blue jacket is hers.', '那件蓝夹克是她的。'),
  ('684a67c4-1186-4d0c-a261-03efe28af195-ex2', '684a67c4-1186-4d0c-a261-03efe28af195', 'hers', 'The royalties accruing under the patent are hers to administer.', '该专利项下产生的使用费由她支配。'),
  ('d9c5468f-3035-4f20-b8f1-5f34c400cb9b-ex1', 'd9c5468f-3035-4f20-b8f1-5f34c400cb9b', 'pastor', 'The pastor welcomed the new members.', '牧师欢迎新成员加入。'),
  ('d9c5468f-3035-4f20-b8f1-5f34c400cb9b-ex2', 'd9c5468f-3035-4f20-b8f1-5f34c400cb9b', 'pastor', 'The tribunal heard testimony regarding records the pastor had maintained.', '法庭听取了有关这位牧师所保存记录的证词。'),
  ('2f5cda80-f615-4eb8-9d15-8ef818db5325-ex1', '2f5cda80-f615-4eb8-9d15-8ef818db5325', 'jazz', 'He plays jazz on the weekends.', '他周末演奏爵士乐。'),
  ('2f5cda80-f615-4eb8-9d15-8ef818db5325-ex2', '2f5cda80-f615-4eb8-9d15-8ef818db5325', 'jazz', 'The jazz archive was digitized under a cross-border preservation accord.', '这批爵士乐档案根据跨境保护协议完成了数字化。'),
  ('75653111-a7a0-47c3-aa24-7c7596482100-ex1', '75653111-a7a0-47c3-aa24-7c7596482100', 'opera', 'We went to the opera last night.', '我们昨晚去看了歌剧。'),
  ('75653111-a7a0-47c3-aa24-7c7596482100-ex2', '75653111-a7a0-47c3-aa24-7c7596482100', 'opera', 'The restored opera house anchors the city''s cultural regeneration strategy.', '修复后的歌剧院是该市文化复兴战略的支柱。'),
  ('3d96a3fb-4280-4a02-91ed-b528a5062837-ex1', '3d96a3fb-4280-4a02-91ed-b528a5062837', 'acquisition', 'The company announced a major acquisition.', '公司宣布了一项重大收购。'),
  ('3d96a3fb-4280-4a02-91ed-b528a5062837-ex2', '3d96a3fb-4280-4a02-91ed-b528a5062837', 'acquisition', 'The acquisition was conditioned on clearance from the competition authority.', '这笔收购以竞争主管机构的批准为先决条件。'),
  ('c1a971c7-0505-48ab-941f-e94cd349f5d9-ex1', 'c1a971c7-0505-48ab-941f-e94cd349f5d9', 'pit', 'The miners worked deep in the pit.', '矿工们在矿井深处工作。'),
  ('c1a971c7-0505-48ab-941f-e94cd349f5d9-ex2', 'c1a971c7-0505-48ab-941f-e94cd349f5d9', 'pit', 'The abandoned pit remains a contamination source decades after closure.', '这座废弃矿坑在关闭数十年后仍是污染源。'),
  ('ab85931b-56d0-4c38-bad8-d9ef3c60e6da-ex1', 'ab85931b-56d0-4c38-bad8-d9ef3c60e6da', 'hug', 'She gave her friend a warm hug.', '她给了朋友一个温暖的拥抱。'),
  ('ab85931b-56d0-4c38-bad8-d9ef3c60e6da-ex2', 'ab85931b-56d0-4c38-bad8-d9ef3c60e6da', 'hug', 'The summit''s choreographed hug belied the underlying tensions.', '峰会上精心安排的拥抱掩盖了潜在的紧张关系。'),
  ('9ce8885f-1fed-4717-b78d-ef34fe1a5ea3-ex1', '9ce8885f-1fed-4717-b78d-ef34fe1a5ea3', 'hay', 'The farmer stored hay for winter.', '农民为过冬储存干草。'),
  ('9ce8885f-1fed-4717-b78d-ef34fe1a5ea3-ex2', '9ce8885f-1fed-4717-b78d-ef34fe1a5ea3', 'hay', 'Investigators struggled to find the needle in a haystack of records.', '调查人员在堆积如山的记录中费力寻找关键线索。'),
  ('ade45132-188a-486d-b532-d93cc6a09ee4-ex1', 'ade45132-188a-486d-b532-d93cc6a09ee4', 'punish', 'The teacher punished the cheating student.', '老师惩罚了作弊的学生。'),
  ('ade45132-188a-486d-b532-d93cc6a09ee4-ex2', 'ade45132-188a-486d-b532-d93cc6a09ee4', 'punish', 'The framework punishes systemic breaches more severely than isolated lapses.', '该框架对系统性违规的处罚重于对孤立失误的处罚。'),
  ('91bee4b0-3331-4445-a117-851f8c26b8b2-ex1', '91bee4b0-3331-4445-a117-851f8c26b8b2', 'equity', 'They built up equity in their home.', '他们在房产中积累了净值。'),
  ('91bee4b0-3331-4445-a117-851f8c26b8b2-ex2', '91bee4b0-3331-4445-a117-851f8c26b8b2', 'equity', 'The bonds convert into equity upon a specified trigger event.', '这些债券在特定触发事件发生时转换为股权。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('ffb73c84-1fe1-4c69-8a9d-55ffcacf7c44-ex1', 'ffb73c84-1fe1-4c69-8a9d-55ffcacf7c44', 'doorway', 'She stood in the doorway smiling.', '她站在门口微笑。'),
  ('ffb73c84-1fe1-4c69-8a9d-55ffcacf7c44-ex2', 'ffb73c84-1fe1-4c69-8a9d-55ffcacf7c44', 'doorway', 'The reform stands in the doorway between aspiration and enforceable obligation.', '这项改革正处于愿景与可执行义务之间的门槛上。'),
  ('eabc835f-3f8d-4311-aa32-a9012fed2309-ex1', 'eabc835f-3f8d-4311-aa32-a9012fed2309', 'departure', 'Our departure is at six tomorrow.', '我们明天六点出发。'),
  ('eabc835f-3f8d-4311-aa32-a9012fed2309-ex2', 'eabc835f-3f8d-4311-aa32-a9012fed2309', 'departure', 'The ruling marks a sharp departure from settled appellate doctrine.', '这一裁决与已确立的上诉判例形成了重大背离。'),
  ('52114355-748e-41f3-afb8-b3b57148a7ae-ex1', '52114355-748e-41f3-afb8-b3b57148a7ae', 'elevator', 'Take the elevator to the third floor.', '坐电梯到三楼。'),
  ('52114355-748e-41f3-afb8-b3b57148a7ae-ex2', '52114355-748e-41f3-afb8-b3b57148a7ae', 'elevator', 'The accessibility code requires compliant elevators in all public buildings.', '无障碍规范要求所有公共建筑配备合规的电梯。'),
  ('9cbc8e94-7d1f-489e-97a1-80aea4e5673e-ex1', '9cbc8e94-7d1f-489e-97a1-80aea4e5673e', 'teenage', 'She has two teenage sons.', '她有两个十几岁的儿子。'),
  ('9cbc8e94-7d1f-489e-97a1-80aea4e5673e-ex2', '9cbc8e94-7d1f-489e-97a1-80aea4e5673e', 'teenage', 'The foundation funds programs keeping teenage girls in secondary education.', '该基金会资助让少女继续接受中学教育的项目。'),
  ('db4eb8e3-4097-4ffa-b362-1dc6c432cdb0-ex1', 'db4eb8e3-4097-4ffa-b362-1dc6c432cdb0', 'guidance', 'Thank you for your guidance.', '感谢你的指导。'),
  ('db4eb8e3-4097-4ffa-b362-1dc6c432cdb0-ex2', 'db4eb8e3-4097-4ffa-b362-1dc6c432cdb0', 'guidance', 'The central bank declined to issue further guidance pending the data.', '在数据公布前，央行拒绝发布进一步的指引。'),
  ('ce963ac0-633a-4893-8859-2ebfcf87ea04-ex1', 'ce963ac0-633a-4893-8859-2ebfcf87ea04', 'happiness', 'Money cannot buy happiness.', '金钱买不到幸福。'),
  ('ce963ac0-633a-4893-8859-2ebfcf87ea04-ex2', 'ce963ac0-633a-4893-8859-2ebfcf87ea04', 'happiness', 'The constitution recognizes the pursuit of happiness as an inalienable aim.', '宪法将追求幸福确认为一项不可剥夺的目标。'),
  ('d2ebbcc8-fd52-45a7-908d-bbfe7b04894d-ex1', 'd2ebbcc8-fd52-45a7-908d-bbfe7b04894d', 'statue', 'The statue stands in the square.', '雕像矗立在广场上。'),
  ('d2ebbcc8-fd52-45a7-908d-bbfe7b04894d-ex2', 'd2ebbcc8-fd52-45a7-908d-bbfe7b04894d', 'statue', 'The statue''s removal reignited a contested debate over public memory.', '这座雕像的移除重新点燃了关于公共记忆的争议。'),
  ('fedffd6f-0a71-496d-8faf-759009559f18-ex1', 'fedffd6f-0a71-496d-8faf-759009559f18', 'pursuit', 'He left in pursuit of the thief.', '他追着小偷跑了。'),
  ('fedffd6f-0a71-496d-8faf-759009559f18-ex2', 'fedffd6f-0a71-496d-8faf-759009559f18', 'pursuit', 'The restriction must serve the pursuit of a legitimate public aim.', '该限制必须服务于追求正当公共目标。'),
  ('b5b319b0-ef8d-4d1d-95a9-d68b7c0a114d-ex1', 'b5b319b0-ef8d-4d1d-95a9-d68b7c0a114d', 'repair', 'The car needs a repair.', '这辆车需要修理。'),
  ('b5b319b0-ef8d-4d1d-95a9-d68b7c0a114d-ex2', 'b5b319b0-ef8d-4d1d-95a9-d68b7c0a114d', 'repair', 'The operator is contractually obliged to repair defects within the warranty period.', '运营方负有在保修期内修复缺陷的合同义务。'),
  ('a8f7ffd9-5749-4bb9-bcd4-907882348ab5-ex1', 'a8f7ffd9-5749-4bb9-bcd4-907882348ab5', 'decent', 'They served a decent meal.', '他们端上了一顿像样的饭菜。'),
  ('a8f7ffd9-5749-4bb9-bcd4-907882348ab5-ex2', 'a8f7ffd9-5749-4bb9-bcd4-907882348ab5', 'decent', 'The settlement offered claimants a decent prospect of recovering their losses.', '和解方案为索赔人提供了挽回损失的现实机会。'),
  ('a4133fd8-5a2b-46be-aff6-28bcaeda0887-ex1', 'a4133fd8-5a2b-46be-aff6-28bcaeda0887', 'gym', 'I go to the gym three times a week.', '我每周去三次健身房。'),
  ('a4133fd8-5a2b-46be-aff6-28bcaeda0887-ex2', 'a4133fd8-5a2b-46be-aff6-28bcaeda0887', 'gym', 'The school''s gym doubled as the emergency shelter during the flood.', '洪灾期间，学校的体育馆兼作应急避难所。'),
  ('10301432-0b54-41cd-b9c0-21d6e01b62de-ex1', '10301432-0b54-41cd-b9c0-21d6e01b62de', 'oral', 'We have an oral exam tomorrow.', '我们明天有口语考试。'),
  ('10301432-0b54-41cd-b9c0-21d6e01b62de-ex2', '10301432-0b54-41cd-b9c0-21d6e01b62de', 'oral', 'Oral assurances unsupported by writing seldom bind a sophisticated party.', '没有书面支持的口头保证很少能约束有经验的当事方。'),
  ('e5dd8fe5-88d7-49a0-89ed-0e166fbe2824-ex1', 'e5dd8fe5-88d7-49a0-89ed-0e166fbe2824', 'clerk', 'The clerk handed me the receipt.', '店员把收据递给我。'),
  ('e5dd8fe5-88d7-49a0-89ed-0e166fbe2824-ex2', 'e5dd8fe5-88d7-49a0-89ed-0e166fbe2824', 'clerk', 'The court clerk certified the record before transmitting it on appeal.', '法院书记员在移交上诉案卷前对其进行了认证。'),
  ('60d34f03-db23-4bc9-83f9-ab8b56833be3-ex1', '60d34f03-db23-4bc9-83f9-ab8b56833be3', 'envelope', 'Please seal the envelope.', '请把信封封好。'),
  ('60d34f03-db23-4bc9-83f9-ab8b56833be3-ex2', '60d34f03-db23-4bc9-83f9-ab8b56833be3', 'envelope', 'The scheme pushed the envelope of permissible accounting until it snapped.', '该方案不断试探可允许会计处理的极限，直到崩盘。'),
  ('50b7a3e0-e005-4faf-b375-bf6b609c4884-ex1', '50b7a3e0-e005-4faf-b375-bf6b609c4884', 'reporting', 'The reporting on the event was thorough.', '对该事件的报道很全面。'),
  ('50b7a3e0-e005-4faf-b375-bf6b609c4884-ex2', '50b7a3e0-e005-4faf-b375-bf6b609c4884', 'reporting', 'The framework mandates timely reporting of exposures to the supervisor.', '该框架要求及时向监管者报告风险敞口。'),
  ('bda24d97-f8fd-4ef2-be0a-bc5bb0402ed5-ex1', 'bda24d97-f8fd-4ef2-be0a-bc5bb0402ed5', 'destination', 'What is your final destination?', '你的最终目的地是哪里？'),
  ('bda24d97-f8fd-4ef2-be0a-bc5bb0402ed5-ex2', 'bda24d97-f8fd-4ef2-be0a-bc5bb0402ed5', 'destination', 'The funds were routed through intermediaries to obscure their ultimate destination.', '这些资金经由中介周转，以掩盖其最终去向。'),
  ('e276e9fa-2233-4b3b-9fa6-d41140951af2-ex1', 'e276e9fa-2233-4b3b-9fa6-d41140951af2', 'fist', 'He clenched his fist in anger.', '他愤怒地握紧了拳头。'),
  ('e276e9fa-2233-4b3b-9fa6-d41140951af2-ex2', 'e276e9fa-2233-4b3b-9fa6-d41140951af2', 'fist', 'The faction maintained an iron fist over the legislative agenda.', '这个派系牢牢掌控着立法议程。'),
  ('d5f306b9-591c-430b-a4c7-df279822f5c2-ex1', 'd5f306b9-591c-430b-a4c7-df279822f5c2', 'endorse', 'The star endorsed the new product.', '明星为这款新产品代言。'),
  ('d5f306b9-591c-430b-a4c7-df279822f5c2-ex2', 'd5f306b9-591c-430b-a4c7-df279822f5c2', 'endorse', 'The commission declined to endorse the methodology as adequately validated.', '委员会拒绝认可该方法已得到充分验证。'),
  ('100e921c-317b-411a-bb40-ab2a79d31763-ex1', '100e921c-317b-411a-bb40-ab2a79d31763', 'exploration', 'Space exploration fascinates me.', '太空探索让我着迷。'),
  ('100e921c-317b-411a-bb40-ab2a79d31763-ex2', '100e921c-317b-411a-bb40-ab2a79d31763', 'exploration', 'The treaty governs the peaceful exploration of resources beneath the seabed.', '该条约规范对海床下资源的和平勘探。'),
  ('4edc242b-8a54-44e3-9b3a-1060927930d4-ex1', '4edc242b-8a54-44e3-9b3a-1060927930d4', 'generous', 'She is generous with her time.', '她乐于付出自己的时间。'),
  ('4edc242b-8a54-44e3-9b3a-1060927930d4-ex2', '4edc242b-8a54-44e3-9b3a-1060927930d4', 'generous', 'The exemption was so generous as to swallow the rule it qualified.', '这一豁免如此宽泛，以至于架空了它所限定的规则。'),
  ('ee4a74fc-4c86-43cc-bfb0-67193b47cdd0-ex1', 'ee4a74fc-4c86-43cc-bfb0-67193b47cdd0', 'bath', 'The baby takes a bath at night.', '宝宝晚上洗澡。'),
  ('ee4a74fc-4c86-43cc-bfb0-67193b47cdd0-ex2', 'ee4a74fc-4c86-43cc-bfb0-67193b47cdd0', 'bath', 'Investors took a bath on holdings the prospectus had materially overstated.', '投资者在招股书严重夸大的持仓上损失惨重。'),
  ('078f3561-5bea-4d82-a8d7-c5301f50d859-ex1', '078f3561-5bea-4d82-a8d7-c5301f50d859', 'thereby', 'He saved money, thereby buying a car.', '他攒了钱，从而买了车。'),
  ('078f3561-5bea-4d82-a8d7-c5301f50d859-ex2', '078f3561-5bea-4d82-a8d7-c5301f50d859', 'thereby', 'The notice was defective, thereby rendering the purported termination void.', '该通知存在瑕疵，从而使所声称的终止归于无效。'),
  ('fcf5c5b7-4bcf-4609-bf5f-c23cb05f2201-ex1', 'fcf5c5b7-4bcf-4609-bf5f-c23cb05f2201', 'indicator', 'The light is an indicator of power.', '这个灯是电源指示。'),
  ('fcf5c5b7-4bcf-4609-bf5f-c23cb05f2201-ex2', 'fcf5c5b7-4bcf-4609-bf5f-c23cb05f2201', 'indicator', 'Early indicators of distress were ignored until the crisis became unavoidable.', '困境的早期指标一直被忽视，直到危机不可避免。'),
  ('24278e5b-cb89-4cb8-a52e-fd971d582a44-ex1', '24278e5b-cb89-4cb8-a52e-fd971d582a44', 'sunlight', 'The plant needs plenty of sunlight.', '这株植物需要充足的阳光。'),
  ('24278e5b-cb89-4cb8-a52e-fd971d582a44-ex2', '24278e5b-cb89-4cb8-a52e-fd971d582a44', 'sunlight', 'Disclosure, like sunlight, remains the best disinfectant against misconduct.', '披露犹如阳光，仍是对付不当行为的最佳消毒剂。'),
  ('94813bf8-cada-423c-b93f-3df67c6bfce9-ex1', '94813bf8-cada-423c-b93f-3df67c6bfce9', 'feedback', 'Thank you for your feedback.', '感谢你的反馈。'),
  ('94813bf8-cada-423c-b93f-3df67c6bfce9-ex2', '94813bf8-cada-423c-b93f-3df67c6bfce9', 'feedback', 'The consultation feedback was subsequently embodied in the final rule.', '这次磋商的反馈意见随后被纳入最终规则。'),
  ('f0823d8e-318b-4b1d-8334-b0bce7b84f69-ex1', 'f0823d8e-318b-4b1d-8334-b0bce7b84f69', 'spectrum', 'The rainbow shows a spectrum of colors.', '彩虹呈现出一系列色彩。'),
  ('f0823d8e-318b-4b1d-8334-b0bce7b84f69-ex2', 'f0823d8e-318b-4b1d-8334-b0bce7b84f69', 'spectrum', 'The resolution drew support from delegates across the political spectrum.', '该决议获得了各政治派别代表的支持。'),
  ('b22c0ac9-f1f4-4444-b0d9-f2a712ce9219-ex1', 'b22c0ac9-f1f4-4444-b0d9-f2a712ce9219', 'purple', 'She wore a purple scarf.', '她戴着一条紫色围巾。'),
  ('b22c0ac9-f1f4-4444-b0d9-f2a712ce9219-ex2', 'b22c0ac9-f1f4-4444-b0d9-f2a712ce9219', 'purple', 'The prose, purple and overwrought, obscured the report''s substantive findings.', '那些辞藻华丽、矫揉造作的文字掩盖了报告的实质性结论。'),
  ('c8991193-b3bc-4a88-bd03-c4dbe4c54697-ex1', 'c8991193-b3bc-4a88-bd03-c4dbe4c54697', 'laser', 'The laser pointer is very bright.', '这支激光笔很亮。'),
  ('c8991193-b3bc-4a88-bd03-c4dbe4c54697-ex2', 'c8991193-b3bc-4a88-bd03-c4dbe4c54697', 'laser', 'The surgeon employed a laser technique that minimized tissue damage.', '外科医生采用了一种将组织损伤降至最低的激光技术。'),
  ('096e5e06-a43e-4fb0-bd08-a50f49ebff8a-ex1', '096e5e06-a43e-4fb0-bd08-a50f49ebff8a', 'bold', 'That was a bold move.', '那是个大胆的举动。'),
  ('096e5e06-a43e-4fb0-bd08-a50f49ebff8a-ex2', '096e5e06-a43e-4fb0-bd08-a50f49ebff8a', 'bold', 'The bold restructuring proved more prudent than its critics had feared.', '这场大胆的重组被证明比批评者所担心的更为审慎。'),
  ('da767099-125d-4679-97d9-0bbb99ee3247-ex1', 'da767099-125d-4679-97d9-0bbb99ee3247', 'reluctant', 'She was reluctant to leave.', '她不愿离开。'),
  ('da767099-125d-4679-97d9-0bbb99ee3247-ex2', 'da767099-125d-4679-97d9-0bbb99ee3247', 'reluctant', 'Banks grew reluctant to lend even to manifestly viable enterprises.', '银行变得不愿放贷，甚至对明显有生存能力的企业也是如此。'),
  ('bedaef76-f0cd-4176-b887-4885852a314a-ex1', 'bedaef76-f0cd-4176-b887-4885852a314a', 'starting', 'What is your starting salary?', '你的起薪是多少？'),
  ('bedaef76-f0cd-4176-b887-4885852a314a-ex2', 'bedaef76-f0cd-4176-b887-4885852a314a', 'starting', 'The starting point of any analysis must be the statute''s plain text.', '任何分析的出发点都必须是法规的字面文本。'),
  ('c76a092f-8af9-464d-9bcb-42895846292f-ex1', 'c76a092f-8af9-464d-9bcb-42895846292f', 'expertise', 'Her expertise in law is impressive.', '她在法律方面的专长令人钦佩。'),
  ('c76a092f-8af9-464d-9bcb-42895846292f-ex2', 'c76a092f-8af9-464d-9bcb-42895846292f', 'expertise', 'The agency lacked the expertise to audit increasingly complex derivatives.', '该机构缺乏审计日益复杂衍生品的专业能力。'),
  ('d0f92bbf-08fd-4577-8a62-64bc0587d6d6-ex1', 'd0f92bbf-08fd-4577-8a62-64bc0587d6d6', 'practically', 'The room was practically empty.', '房间几乎是空的。'),
  ('d0f92bbf-08fd-4577-8a62-64bc0587d6d6-ex2', 'd0f92bbf-08fd-4577-8a62-64bc0587d6d6', 'practically', 'Verification proved practically impossible given the destroyed records.', '由于记录被销毁，核查实际上无法进行。'),
  ('eacf4d10-d4a5-4e6b-84b7-d9eff3351178-ex1', 'eacf4d10-d4a5-4e6b-84b7-d9eff3351178', 'eating', 'Eating vegetables is healthy.', '吃蔬菜有益健康。'),
  ('eacf4d10-d4a5-4e6b-84b7-d9eff3351178-ex2', 'eacf4d10-d4a5-4e6b-84b7-d9eff3351178', 'eating', 'Rising costs are eating into margins across even efficient producers.', '成本上升正在侵蚀即使是高效生产商的利润。'),
  ('211228d0-9277-4eeb-a54a-46767dabecfe-ex1', '211228d0-9277-4eeb-a54a-46767dabecfe', 'hint', 'Give me a hint about the answer.', '给我一点答案的提示。'),
  ('211228d0-9277-4eeb-a54a-46767dabecfe-ex2', '211228d0-9277-4eeb-a54a-46767dabecfe', 'hint', 'There was no hint of the liabilities later disclosed in the restatement.', '重述中后来披露的负债事先毫无迹象。'),
  ('72ae0041-be35-4e25-9d01-2559bce4294f-ex1', '72ae0041-be35-4e25-9d01-2559bce4294f', 'sharply', 'Prices rose sharply this week.', '本周物价急剧上涨。'),
  ('72ae0041-be35-4e25-9d01-2559bce4294f-ex2', '72ae0041-be35-4e25-9d01-2559bce4294f', 'sharply', 'The justices divided sharply over the proper construction of the clause.', '大法官们在该条款的正确解释上严重分歧。'),
  ('4c0782ef-647d-4b77-bee9-194f7d99bccb-ex1', '4c0782ef-647d-4b77-bee9-194f7d99bccb', 'parade', 'The kids watched the parade.', '孩子们观看了游行。'),
  ('4c0782ef-647d-4b77-bee9-194f7d99bccb-ex2', '4c0782ef-647d-4b77-bee9-194f7d99bccb', 'parade', 'The disclosures paraded failures the institution had long sought to conceal.', '这些披露暴露了该机构长期试图掩盖的失误。'),
  ('e51473ec-1e58-4d3a-a172-0373da706d57-ex1', 'e51473ec-1e58-4d3a-a172-0373da706d57', 'realm', 'That is outside my realm of knowledge.', '那超出了我的知识范围。'),
  ('e51473ec-1e58-4d3a-a172-0373da706d57-ex2', 'e51473ec-1e58-4d3a-a172-0373da706d57', 'realm', 'The dispute crossed from the commercial realm into the constitutional.', '这场争议从商业领域跨入了宪法领域。'),
  ('35f0a4ef-902a-43e5-b342-2870833d0a62-ex1', '35f0a4ef-902a-43e5-b342-2870833d0a62', 'cancel', 'They canceled the flight.', '他们取消了航班。'),
  ('35f0a4ef-902a-43e5-b342-2870833d0a62-ex2', '35f0a4ef-902a-43e5-b342-2870833d0a62', 'cancel', 'The board moved to cancel the merger after due diligence exposed hidden liabilities.', '尽职调查发现隐性负债后，董事会着手取消合并。'),
  ('fd740f2a-f441-4498-b053-a03b38e7490c-ex1', 'fd740f2a-f441-4498-b053-a03b38e7490c', 'blend', 'The smoothie is a blend of fruits.', '这杯果昔是多种水果的混合。'),
  ('fd740f2a-f441-4498-b053-a03b38e7490c-ex2', 'fd740f2a-f441-4498-b053-a03b38e7490c', 'blend', 'The policy blends mandates with incentives calibrated by sector.', '该政策将强制要求与按行业调配的激励措施融为一体。'),
  ('7b6a772f-cd58-4448-96fd-25ba55336538-ex1', '7b6a772f-cd58-4448-96fd-25ba55336538', 'therapist', 'She sees a therapist every week.', '她每周看一次治疗师。'),
  ('7b6a772f-cd58-4448-96fd-25ba55336538-ex2', '7b6a772f-cd58-4448-96fd-25ba55336538', 'therapist', 'The therapist''s privileged notes were shielded from compelled disclosure.', '治疗师的特权记录受保护，免于被强制披露。'),
  ('14bbec79-b66b-4cc2-806b-28fe7d19c52d-ex1', '14bbec79-b66b-4cc2-806b-28fe7d19c52d', 'peel', 'Peel the orange before eating.', '吃橙子前先剥皮。'),
  ('14bbec79-b66b-4cc2-806b-28fe7d19c52d-ex2', '14bbec79-b66b-4cc2-806b-28fe7d19c52d', 'peel', 'Unwinding the structure resembled peeling away nested layers of entities.', '拆解这一架构就像剥开层层嵌套的实体。'),
  ('a5b98125-a241-4549-be00-a26bf5c095ee-ex1', 'a5b98125-a241-4549-be00-a26bf5c095ee', 'pizza', 'Let''s order a pizza tonight.', '今晚我们点披萨吧。'),
  ('a5b98125-a241-4549-be00-a26bf5c095ee-ex2', 'a5b98125-a241-4549-be00-a26bf5c095ee', 'pizza', 'The trademark dispute over the restaurant''s signature pizza reached the courts.', '围绕这家餐厅招牌披萨的商标纠纷诉至法院。'),
  ('766930da-3df2-40db-a501-e7a31d568286-ex1', '766930da-3df2-40db-a501-e7a31d568286', 'recipient', 'The recipient signed for the package.', '收件人签收了包裹。'),
  ('766930da-3df2-40db-a501-e7a31d568286-ex2', '766930da-3df2-40db-a501-e7a31d568286', 'recipient', 'Each grant recipient must account for the funds under audited conditions.', '每位资助接受者都必须在审计条件下对资金作出说明。'),
  ('cf4b10b9-a1eb-42cc-84ac-cdfd347d129e-ex1', 'cf4b10b9-a1eb-42cc-84ac-cdfd347d129e', 'hesitate', 'Don''t hesitate to ask for help.', '需要帮助尽管开口。'),
  ('cf4b10b9-a1eb-42cc-84ac-cdfd347d129e-ex2', 'cf4b10b9-a1eb-42cc-84ac-cdfd347d129e', 'hesitate', 'The court did not hesitate to set aside an award procured through fraud.', '法院毫不犹豫地撤销了通过欺诈取得的裁决。'),
  ('48d67c69-2590-4445-b089-3c6ca4387f92-ex1', '48d67c69-2590-4445-b089-3c6ca4387f92', 'flip', 'Flip the pancake carefully.', '小心地翻动煎饼。'),
  ('48d67c69-2590-4445-b089-3c6ca4387f92-ex2', '48d67c69-2590-4445-b089-3c6ca4387f92', 'flip', 'Sentiment can flip overnight when counterparties withdraw their credit lines.', '当交易对手撤回信贷额度时，市场情绪可能一夜逆转。'),
  ('f02867a8-ddd8-4cef-898a-2167922c2900-ex1', 'f02867a8-ddd8-4cef-898a-2167922c2900', 'accounting', 'She studies accounting at college.', '她在大学学习会计。'),
  ('f02867a8-ddd8-4cef-898a-2167922c2900-ex2', 'f02867a8-ddd8-4cef-898a-2167922c2900', 'accounting', 'The aggressive accounting treatment masked liabilities the audit later exposed.', '激进的会计处理掩盖了后来被审计揭露的负债。'),
  ('2d657580-0dd6-4ddf-addc-5229d23a4be5-ex1', '2d657580-0dd6-4ddf-addc-5229d23a4be5', 'bias', 'The report shows clear bias.', '这份报告带有明显偏见。'),
  ('2d657580-0dd6-4ddf-addc-5229d23a4be5-ex2', '2d657580-0dd6-4ddf-addc-5229d23a4be5', 'bias', 'Adjudicators must avoid even the appearance of bias toward either party.', '裁判者必须避免对任何一方表现出哪怕表面上的偏见。'),
  ('16bb816e-9c7d-4328-b8ba-76d60a7686bf-ex1', '16bb816e-9c7d-4328-b8ba-76d60a7686bf', 'huh', 'Huh? Could you say that again?', '啊？你能再说一遍吗？'),
  ('16bb816e-9c7d-4328-b8ba-76d60a7686bf-ex2', '16bb816e-9c7d-4328-b8ba-76d60a7686bf', 'huh', '"Huh," the analyst murmured, noticing the figures no longer reconciled.', '“嗯？”分析师低声说，注意到这些数字已经对不上了。'),
