  ('32c06fcf-0260-48d0-9992-2b6e0d06bbb3-ex1', '32c06fcf-0260-48d0-9992-2b6e0d06bbb3', 'broker', 'The broker arranged the sale.', '经纪人安排了这笔买卖。'),
  ('32c06fcf-0260-48d0-9992-2b6e0d06bbb3-ex2', '32c06fcf-0260-48d0-9992-2b6e0d06bbb3', 'broker', 'The envoy brokered the compromise that salvaged the final communiqué.', '这位特使促成的折中方案挽救了最终公报。'),
  ('f5a4e8d7-622c-4e01-90b3-ff506aee3904-ex1', 'f5a4e8d7-622c-4e01-90b3-ff506aee3904', 'treasure', 'The children searched for treasure.', '孩子们寻找宝藏。'),
  ('f5a4e8d7-622c-4e01-90b3-ff506aee3904-ex2', 'f5a4e8d7-622c-4e01-90b3-ff506aee3904', 'treasure', 'The archive is a treasure that scholars had long believed lost.', '这份档案是学者们长期以为已经佚失的瑰宝。'),
  ('63ab2408-b77e-42ed-8781-92b2492bd6f6-ex1', '63ab2408-b77e-42ed-8781-92b2492bd6f6', 'loyalty', 'The dog showed great loyalty.', '这只狗表现出极大的忠诚。'),
  ('63ab2408-b77e-42ed-8781-92b2492bd6f6-ex2', '63ab2408-b77e-42ed-8781-92b2492bd6f6', 'loyalty', 'Counsel owes an undivided duty of loyalty to the client.', '律师对客户负有不可分割的忠实义务。'),
  ('1ea6b988-334e-489b-8ceb-de60cd83616d-ex1', '1ea6b988-334e-489b-8ceb-de60cd83616d', 'talented', 'She is a talented painter.', '她是个有才华的画家。'),
  ('1ea6b988-334e-489b-8ceb-de60cd83616d-ex2', '1ea6b988-334e-489b-8ceb-de60cd83616d', 'talented', 'Retention of talented staff has become a strategic regulatory concern.', '留住有才能的员工已成为一个战略性的监管关切。'),
  ('7d1281c2-bdf6-40ff-8ba9-250f81658d3d-ex1', '7d1281c2-bdf6-40ff-8ba9-250f81658d3d', 'gasoline', 'We need to fill up on gasoline.', '我们得加油了。'),
  ('7d1281c2-bdf6-40ff-8ba9-250f81658d3d-ex2', '7d1281c2-bdf6-40ff-8ba9-250f81658d3d', 'gasoline', 'Subsidized gasoline prices fuel both fiscal deficits and overconsumption.', '汽油补贴价格加剧了财政赤字和过度消费。'),
  ('8b8ebd6a-54a3-48c5-9331-8ccc01db6b2c-ex1', '8b8ebd6a-54a3-48c5-9331-8ccc01db6b2c', 'stiff', 'My neck is stiff this morning.', '今天早上我脖子僵硬。'),
  ('8b8ebd6a-54a3-48c5-9331-8ccc01db6b2c-ex2', '8b8ebd6a-54a3-48c5-9331-8ccc01db6b2c', 'stiff', 'The violations attracted stiff penalties scaled to corporate revenue.', '这些违规行为招致了按企业营收比例确定的严厉处罚。'),
  ('d8b5c7ac-b5ee-41bc-806f-3ff45ec68118-ex1', 'd8b5c7ac-b5ee-41bc-806f-3ff45ec68118', 'output', 'The factory''s output doubled.', '工厂的产量翻了一番。'),
  ('d8b5c7ac-b5ee-41bc-806f-3ff45ec68118-ex2', 'd8b5c7ac-b5ee-41bc-806f-3ff45ec68118', 'output', 'Real output stagnated despite sustained gains in measured productivity.', '尽管测量到的生产率持续提升，实际产出却停滞不前。'),
  ('9c5050b8-d2a3-47f6-b4f4-730f7b5d917a-ex1', '9c5050b8-d2a3-47f6-b4f4-730f7b5d917a', 'nominee', 'The nominee accepted the award graciously.', '被提名者优雅地接受了奖项。'),
  ('9c5050b8-d2a3-47f6-b4f4-730f7b5d917a-ex2', '9c5050b8-d2a3-47f6-b4f4-730f7b5d917a', 'nominee', 'The shares were held through nominees to obscure the controlling interest.', '这些股份通过代持人持有，以掩盖控股权益。'),
  ('7a06567d-cdab-403e-80d0-f93b55d37c21-ex1', '7a06567d-cdab-403e-80d0-f93b55d37c21', 'extended', 'We took an extended vacation.', '我们休了一个长假。'),
  ('7a06567d-cdab-403e-80d0-f93b55d37c21-ex2', '7a06567d-cdab-403e-80d0-f93b55d37c21', 'extended', 'The extended suspension required periodic reauthorization by the board.', '延长的停职令需要董事会定期重新授权。'),
  ('7c68f722-9ad3-43c8-b687-cc73daff3c4e-ex1', '7c68f722-9ad3-43c8-b687-cc73daff3c4e', 'diabetes', 'He was diagnosed with diabetes.', '他被诊断出患有糖尿病。'),
  ('7c68f722-9ad3-43c8-b687-cc73daff3c4e-ex2', '7c68f722-9ad3-43c8-b687-cc73daff3c4e', 'diabetes', 'The strategy targets diet-related risk factors driving rising diabetes rates.', '该战略针对推动糖尿病发病率上升的饮食相关风险因素。'),
  ('dae18763-bc92-4165-8233-9c1273e30cdd-ex1', 'dae18763-bc92-4165-8233-9c1273e30cdd', 'slap', 'She gave him a slap on the back.', '她拍了拍他的背。'),
  ('dae18763-bc92-4165-8233-9c1273e30cdd-ex2', 'dae18763-bc92-4165-8233-9c1273e30cdd', 'slap', 'The token fine amounted to no more than a slap on the wrist.', '这笔象征性罚款不过是轻描淡写的敲打。'),
  ('318b74a8-5d5e-48a1-ac92-aacaa8e02509-ex1', '318b74a8-5d5e-48a1-ac92-aacaa8e02509', 'toxic', 'These fumes are toxic.', '这些烟雾是有毒的。'),
  ('318b74a8-5d5e-48a1-ac92-aacaa8e02509-ex2', '318b74a8-5d5e-48a1-ac92-aacaa8e02509', 'toxic', 'The firm offloaded its toxic assets before the disclosure rules took effect.', '该公司在披露规则生效前抛售了其有毒资产。'),
  ('48950c29-31fd-4cc6-acdb-2f784dc0d733-ex1', '48950c29-31fd-4cc6-acdb-2f784dc0d733', 'alleged', 'The alleged thief was released.', '被指控的窃贼被释放了。'),
  ('48950c29-31fd-4cc6-acdb-2f784dc0d733-ex2', '48950c29-31fd-4cc6-acdb-2f784dc0d733', 'alleged', 'The indictment concerns alleged fraud spanning hundreds of transactions.', '起诉书涉及涉嫌欺诈，涵盖数百笔交易。'),
  ('6cc9757b-01bc-46a6-b7ec-11e0b364db47-ex1', '6cc9757b-01bc-46a6-b7ec-11e0b364db47', 'jaw', 'He broke his jaw in the accident.', '他在事故中下巴骨折了。'),
  ('6cc9757b-01bc-46a6-b7ec-11e0b364db47-ex2', '6cc9757b-01bc-46a6-b7ec-11e0b364db47', 'jaw', 'The figures made even seasoned analysts'' jaws drop.', '这些数字让即使是资深分析师也目瞪口呆。'),
  ('04227450-bd63-435b-add9-0d20237731a2-ex1', '04227450-bd63-435b-add9-0d20237731a2', 'grief', 'She was overcome with grief.', '她悲痛欲绝。'),
  ('04227450-bd63-435b-add9-0d20237731a2-ex2', '04227450-bd63-435b-add9-0d20237731a2', 'grief', 'The compensation could not assuage the grief of the bereaved families.', '赔偿无法抚平丧亲家庭的悲痛。'),
  ('46002a0e-2710-49bc-b896-bb7fbf23d911-ex1', '46002a0e-2710-49bc-b896-bb7fbf23d911', 'mysterious', 'There was a mysterious noise at night.', '夜里有一种神秘的声响。'),
  ('46002a0e-2710-49bc-b896-bb7fbf23d911-ex2', '46002a0e-2710-49bc-b896-bb7fbf23d911', 'mysterious', 'The funds'' destination remained mysterious until the registry data leaked.', '在登记数据泄露之前，这些资金的去向一直成谜。'),
  ('21c6279e-68c8-4455-9f8f-288f98165343-ex1', '21c6279e-68c8-4455-9f8f-288f98165343', 'rocket', 'The rocket launched successfully.', '火箭成功发射。'),
  ('21c6279e-68c8-4455-9f8f-288f98165343-ex2', '21c6279e-68c8-4455-9f8f-288f98165343', 'rocket', 'Housing costs rocketed in metropolitan areas with constrained supply.', '在供应受限的大都市地区，住房成本飞涨。'),
  ('0bda9c2e-6226-43b0-8119-0631940faff5-ex1', '0bda9c2e-6226-43b0-8119-0631940faff5', 'donate', 'She donated books to the library.', '她向图书馆捐赠了图书。'),
  ('0bda9c2e-6226-43b0-8119-0631940faff5-ex2', '0bda9c2e-6226-43b0-8119-0631940faff5', 'donate', 'The foundation agreed to donate substantial grants to vaccine research.', '该基金会同意向疫苗研究捐赠巨额资助。'),
  ('5153f1be-5d84-43e9-80fd-12a3185bc5e1-ex1', '5153f1be-5d84-43e9-80fd-12a3185bc5e1', 'inmate', 'The inmate was released early.', '这名囚犯被提前释放。'),
  ('5153f1be-5d84-43e9-80fd-12a3185bc5e1-ex2', '5153f1be-5d84-43e9-80fd-12a3185bc5e1', 'inmate', 'Every inmate retains rights that incarceration does not extinguish.', '每名在押人员仍保有不因监禁而消灭的权利。'),
  ('a5cbb729-5a15-46c5-a6e3-a954011a8c8a-ex1', 'a5cbb729-5a15-46c5-a6e3-a954011a8c8a', 'tackle', 'We need to tackle this problem now.', '我们现在需要解决这个问题。'),
  ('a5cbb729-5a15-46c5-a6e3-a954011a8c8a-ex2', 'a5cbb729-5a15-46c5-a6e3-a954011a8c8a', 'tackle', 'The reforms tackle the structural drivers rather than the visible symptoms.', '这些改革针对的是结构性根源，而非表面症状。'),
  ('5cb41a2a-a6df-4eff-9324-e369434eb833-ex1', '5cb41a2a-a6df-4eff-9324-e369434eb833', 'dynamics', 'Group dynamics affect the outcome.', '群体动力会影响结果。'),
  ('5cb41a2a-a6df-4eff-9324-e369434eb833-ex2', '5cb41a2a-a6df-4eff-9324-e369434eb833', 'dynamics', 'The merger altered the competitive dynamics of the entire industry.', '此次合并改变了整个行业的竞争格局。'),
  ('5f716b4e-0025-40a1-bd44-020a86734ae6-ex1', '5f716b4e-0025-40a1-bd44-020a86734ae6', 'bow', 'The actor took a bow.', '演员鞠躬谢幕。'),
  ('5f716b4e-0025-40a1-bd44-020a86734ae6-ex2', '5f716b4e-0025-40a1-bd44-020a86734ae6', 'bow', 'The administration refused to bow to demands it deemed unlawful.', '行政当局拒绝向其认定为非法的要求屈服。'),
  ('cad52877-79b1-4b9d-aba3-5ad125a4a89c-ex1', 'cad52877-79b1-4b9d-aba3-5ad125a4a89c', 'ours', 'That house is ours.', '那栋房子是我们的。'),
  ('cad52877-79b1-4b9d-aba3-5ad125a4a89c-ex2', 'cad52877-79b1-4b9d-aba3-5ad125a4a89c', 'ours', 'The responsibility for these resources is ours to discharge for future generations.', '为子孙后代管护这些资源是我们应尽的责任。'),
  ('54d93285-5464-41d6-be27-f81325009e87-ex1', '54d93285-5464-41d6-be27-f81325009e87', 'dignity', 'Treat everyone with dignity.', '以尊严待人。'),
  ('54d93285-5464-41d6-be27-f81325009e87-ex2', '54d93285-5464-41d6-be27-f81325009e87', 'dignity', 'The tribunal held that the conditions violated the detainees'' inherent dignity.', '法庭裁定这些条件侵犯了被拘留者固有的尊严。'),
  ('82a011b4-c5a3-4d02-bd08-3a135a1d67c7-ex1', '82a011b4-c5a3-4d02-bd08-3a135a1d67c7', 'carpet', 'The room has a soft red carpet.', '房间里铺着柔软的红地毯。'),
  ('82a011b4-c5a3-4d02-bd08-3a135a1d67c7-ex2', '82a011b4-c5a3-4d02-bd08-3a135a1d67c7', 'carpet', 'Management attempted to sweep the irregularities under the carpet.', '管理层试图把这些违规行为掩盖过去。'),
  ('ff156381-6916-42bd-90c4-dabbeda350e9-ex1', 'ff156381-6916-42bd-90c4-dabbeda350e9', 'parental', 'Parental support helps children learn.', '父母的支持有助于孩子学习。'),
  ('ff156381-6916-42bd-90c4-dabbeda350e9-ex2', 'ff156381-6916-42bd-90c4-dabbeda350e9', 'parental', 'The act extends parental leave entitlements to every working parent.', '该法案将育儿假权利扩展至每位职场父母。'),
  ('a6254270-07ab-4afa-acff-fc049a98d263-ex1', 'a6254270-07ab-4afa-acff-fc049a98d263', 'bubble', 'The child blew a soap bubble.', '孩子吹了一个肥皂泡。'),
  ('a6254270-07ab-4afa-acff-fc049a98d263-ex2', 'a6254270-07ab-4afa-acff-fc049a98d263', 'bubble', 'The asset bubble burst once the guarantee''s limits became public.', '担保上限公之于众后，资产泡沫随即破裂。'),
  ('6434d15b-d1f8-45cc-98ca-c0209abe9103-ex1', '6434d15b-d1f8-45cc-98ca-c0209abe9103', 'buddy', 'He is my old college buddy.', '他是我大学时的老伙伴。'),
  ('6434d15b-d1f8-45cc-98ca-c0209abe9103-ex2', '6434d15b-d1f8-45cc-98ca-c0209abe9103', 'buddy', 'The buddy system in oversight bred the complacency the inquiry condemned.', '监管中的裙带关系滋生了调查所谴责的自满情绪。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('41f69d08-8181-41d4-a979-05e7d3d8a061-ex1', '41f69d08-8181-41d4-a979-05e7d3d8a061', 'barn', 'The horses sleep in the barn.', '马匹在谷仓里过夜。'),
  ('41f69d08-8181-41d4-a979-05e7d3d8a061-ex2', '41f69d08-8181-41d4-a979-05e7d3d8a061', 'barn', 'The fire destroyed a barn that had stood for over a century.', '大火烧毁了一座矗立逾百年的谷仓。'),
  ('dea96206-b91a-4532-8be5-2b2bb249df5a-ex1', 'dea96206-b91a-4532-8be5-2b2bb249df5a', 'sword', 'The knight carried a heavy sword.', '骑士佩带着一把沉重的剑。'),
  ('dea96206-b91a-4532-8be5-2b2bb249df5a-ex2', 'dea96206-b91a-4532-8be5-2b2bb249df5a', 'sword', 'Aggressive disclosure rules became a double-edged sword for the industry.', '激进的披露规则对该行业而言成了一把双刃剑。'),
  ('7a6499dc-e514-4a56-be66-6994302f87b8-ex1', '7a6499dc-e514-4a56-be66-6994302f87b8', 'seventh', 'Our room is on the seventh floor.', '我们的房间在七楼。'),
  ('7a6499dc-e514-4a56-be66-6994302f87b8-ex2', '7a6499dc-e514-4a56-be66-6994302f87b8', 'seventh', 'The seventh round of negotiations finally produced a binding text.', '第七轮谈判终于产生了有约束力的文本。'),
  ('e436edb8-7c9c-415f-abe9-b9ca21194472-ex1', 'e436edb8-7c9c-415f-abe9-b9ca21194472', 'glory', 'The team enjoyed its moment of glory.', '球队享受着荣耀时刻。'),
  ('e436edb8-7c9c-415f-abe9-b9ca21194472-ex2', 'e436edb8-7c9c-415f-abe9-b9ca21194472', 'glory', 'The institution''s former glory could not excuse its present failings.', '该机构昔日的辉煌不能为其当下的失职开脱。'),
  ('e7591f0a-327c-48d7-99b6-21829aeea4d4-ex1', 'e7591f0a-327c-48d7-99b6-21829aeea4d4', 'tightly', 'Hold the rope tightly.', '紧紧抓住绳子。'),
  ('e7591f0a-327c-48d7-99b6-21829aeea4d4-ex2', 'e7591f0a-327c-48d7-99b6-21829aeea4d4', 'tightly', 'The covenant tightly constrains the borrower''s capacity to incur further debt.', '该契约严格限制借款人进一步举债的能力。'),
  ('e42b7da5-6584-4a83-b432-d7feabedc782-ex1', 'e42b7da5-6584-4a83-b432-d7feabedc782', 'protective', 'She is protective of her children.', '她对自己的孩子很有保护欲。'),
  ('e42b7da5-6584-4a83-b432-d7feabedc782-ex2', 'e42b7da5-6584-4a83-b432-d7feabedc782', 'protective', 'All personnel must wear certified protective equipment within the facility.', '所有人员在设施内必须佩戴经认证的防护装备。'),
  ('d4b2a29f-f847-402e-8aa4-1f2ab45eb4f9-ex1', 'd4b2a29f-f847-402e-8aa4-1f2ab45eb4f9', 'tuck', 'Tuck the blanket around the baby.', '把毯子给宝宝掖好。'),
  ('d4b2a29f-f847-402e-8aa4-1f2ab45eb4f9-ex2', 'd4b2a29f-f847-402e-8aa4-1f2ab45eb4f9', 'tuck', 'The exemption was tucked into the bill during the closing conference.', '这项豁免是在最后协商阶段被悄悄塞进法案的。'),
  ('e60315ef-a004-478e-b0a4-211e236ee235-ex1', 'e60315ef-a004-478e-b0a4-211e236ee235', 'drum', 'He plays the drums in a band.', '他在乐队里打鼓。'),
  ('e60315ef-a004-478e-b0a4-211e236ee235-ex2', 'e60315ef-a004-478e-b0a4-211e236ee235', 'drum', 'Advocacy groups continued to drum up support for the stalled reform.', '倡导团体持续为停滞的改革争取支持。'),
  ('9bab4276-e7a5-4413-a3a4-9a6c2a7a5813-ex1', '9bab4276-e7a5-4413-a3a4-9a6c2a7a5813', 'faint', 'She felt faint in the heat.', '在炎热中她感到头晕。'),
  ('9bab4276-e7a5-4413-a3a4-9a6c2a7a5813-ex2', '9bab4276-e7a5-4413-a3a4-9a6c2a7a5813', 'faint', 'There was not even a faint indication of the liabilities later disclosed.', '后来披露的负债事先连一丝迹象都没有。'),
  ('cff8e7a1-e08a-4332-a799-346607a6e765-ex1', 'cff8e7a1-e08a-4332-a799-346607a6e765', 'queen', 'The queen waved to the crowd.', '女王向人群挥手。'),
  ('cff8e7a1-e08a-4332-a799-346607a6e765-ex2', 'cff8e7a1-e08a-4332-a799-346607a6e765', 'queen', 'The firm became the undisputed queen of a market it effectively monopolized.', '该公司成为它实际垄断的市场中无可争议的霸主。'),
  ('c6e17073-d9bb-4cb6-9039-0e5ef9b763c1-ex1', 'c6e17073-d9bb-4cb6-9039-0e5ef9b763c1', 'dilemma', 'She faced a difficult dilemma.', '她面临着一个艰难的两难抉择。'),
  ('c6e17073-d9bb-4cb6-9039-0e5ef9b763c1-ex2', 'c6e17073-d9bb-4cb6-9039-0e5ef9b763c1', 'dilemma', 'The allocation of scarce medical resources raises profound ethical dilemmas.', '稀缺医疗资源的分配引出了深刻的伦理困境。'),
  ('1768a21c-adbc-44a4-84a0-eef8f2c15cd1-ex1', '1768a21c-adbc-44a4-84a0-eef8f2c15cd1', 'input', 'Thank you for your input.', '感谢你的意见。'),
  ('1768a21c-adbc-44a4-84a0-eef8f2c15cd1-ex2', '1768a21c-adbc-44a4-84a0-eef8f2c15cd1', 'input', 'Rising input costs compressed margins across even efficient producers.', '投入成本上升压缩了即使是高效生产商的利润率。'),
  ('6d967a7e-1787-48fb-9cd4-2e07b44fb63d-ex1', '6d967a7e-1787-48fb-9cd4-2e07b44fb63d', 'specialize', 'She specializes in pediatrics.', '她专攻儿科。'),
  ('6d967a7e-1787-48fb-9cd4-2e07b44fb63d-ex2', '6d967a7e-1787-48fb-9cd4-2e07b44fb63d', 'specialize', 'The tribunal specializes in disputes arising under the trade agreements.', '该法庭专门审理依据贸易协定产生的争端。'),
  ('81b4c25d-21b4-4c0b-9e02-e3d45136e9b1-ex1', '81b4c25d-21b4-4c0b-9e02-e3d45136e9b1', 'northeast', 'The wind came from the northeast.', '风从东北方吹来。'),
  ('81b4c25d-21b4-4c0b-9e02-e3d45136e9b1-ex2', '81b4c25d-21b4-4c0b-9e02-e3d45136e9b1', 'northeast', 'Manufacturing employment declined sharply across the industrial northeast.', '在工业化的东北地区，制造业就业人数急剧下降。'),
  ('285901a9-ffd5-4402-a024-e12f7902863b-ex1', '285901a9-ffd5-4402-a024-e12f7902863b', 'shallow', 'The water here is shallow.', '这里的水很浅。'),
  ('285901a9-ffd5-4402-a024-e12f7902863b-ex2', '285901a9-ffd5-4402-a024-e12f7902863b', 'shallow', 'The evidentiary record was too shallow to sustain the principal allegations.', '证据记录过于单薄，不足以支持主要指控。'),
  ('e29c550e-dd7e-4b46-b8f9-fc43be79ea9a-ex1', 'e29c550e-dd7e-4b46-b8f9-fc43be79ea9a', 'liability', 'The company accepted liability.', '公司承担了责任。'),
  ('e29c550e-dd7e-4b46-b8f9-fc43be79ea9a-ex2', 'e29c550e-dd7e-4b46-b8f9-fc43be79ea9a', 'liability', 'The manufacturer bears strict liability for defects present at distribution.', '制造商对出厂时即存在的缺陷承担严格责任。'),
  ('95099c7a-47ee-46d3-8d98-2184ec9fbbae-ex1', '95099c7a-47ee-46d3-8d98-2184ec9fbbae', 'sail', 'The boat set sail at dawn.', '船在黎明启航。'),
  ('95099c7a-47ee-46d3-8d98-2184ec9fbbae-ex2', '95099c7a-47ee-46d3-8d98-2184ec9fbbae', 'sail', 'The bill sailed through committee before opposition could organize.', '法案在反对派组织起来之前便顺利通过了委员会。'),
  ('54a279f8-76a6-489e-9055-c03c5b32093d-ex1', '54a279f8-76a6-489e-9055-c03c5b32093d', 'merchant', 'The merchant sold spices.', '这位商人贩卖香料。'),
  ('54a279f8-76a6-489e-9055-c03c5b32093d-ex2', '54a279f8-76a6-489e-9055-c03c5b32093d', 'merchant', 'The convention codified merchant custom into binding commercial law.', '该公约将商人惯例编纂为有约束力的商法。'),
  ('30ef70c4-7aa9-4331-b43f-de837d27e8c6-ex1', '30ef70c4-7aa9-4331-b43f-de837d27e8c6', 'stadium', 'The stadium holds fifty thousand people.', '这座体育场可容纳五万人。'),
  ('30ef70c4-7aa9-4331-b43f-de837d27e8c6-ex2', '30ef70c4-7aa9-4331-b43f-de837d27e8c6', 'stadium', 'The stadium deal was underwritten by municipal bonds the city later struggled to service.', '这项球场协议由市政债券支持，而该市后来难以偿付这些债券。'),
  ('086e02a8-95a9-4cdf-a42e-70d3acb7f511-ex1', '086e02a8-95a9-4cdf-a42e-70d3acb7f511', 'improved', 'The improved design is safer.', '改进后的设计更安全。'),
  ('086e02a8-95a9-4cdf-a42e-70d3acb7f511-ex2', '086e02a8-95a9-4cdf-a42e-70d3acb7f511', 'improved', 'The improved screening of donated blood virtually eliminated transfusion infections.', '献血筛查的改进几乎消除了输血感染。'),
  ('693f3841-8401-47d7-a45b-288ccd951b06-ex1', '693f3841-8401-47d7-a45b-288ccd951b06', 'bloody', 'He had a bloody nose.', '他流了鼻血。'),
  ('693f3841-8401-47d7-a45b-288ccd951b06-ex2', '693f3841-8401-47d7-a45b-288ccd951b06', 'bloody', 'The protracted conflict gave way to a bloody and inconclusive stalemate.', '旷日持久的冲突演变为一场血腥而无果的僵局。'),
  ('22b340c2-698f-48ec-b939-30d6fd91f603-ex1', '22b340c2-698f-48ec-b939-30d6fd91f603', 'associated', 'The risks associated with smoking are well known.', '吸烟相关的风险众所周知。'),
  ('22b340c2-698f-48ec-b939-30d6fd91f603-ex2', '22b340c2-698f-48ec-b939-30d6fd91f603', 'associated', 'The costs associated with the breach far exceeded the original estimates.', '与这次泄露相关的成本远超最初的估算。'),
  ('859dd506-f539-41b2-80ea-0e19d733c34f-ex1', '859dd506-f539-41b2-80ea-0e19d733c34f', 'withdrawal', 'I made a withdrawal from the bank.', '我从银行取了钱。'),
  ('859dd506-f539-41b2-80ea-0e19d733c34f-ex2', '859dd506-f539-41b2-80ea-0e19d733c34f', 'withdrawal', 'The abrupt withdrawal of liquidity precipitated the institution''s collapse.', '流动性的骤然抽离加速了该机构的崩溃。'),
  ('c4d1630c-886f-4430-a63d-53bf8102e3fe-ex1', 'c4d1630c-886f-4430-a63d-53bf8102e3fe', 'refrigerator', 'Put the milk in the refrigerator.', '把牛奶放进冰箱。'),
  ('c4d1630c-886f-4430-a63d-53bf8102e3fe-ex2', 'c4d1630c-886f-4430-a63d-53bf8102e3fe', 'refrigerator', 'The energy labeling rules apply to every refrigerator sold within the market.', '能效标签规则适用于市场上销售的每一台冰箱。'),
  ('28429ae2-40ff-4850-a681-3c6ba75d72a5-ex1', '28429ae2-40ff-4850-a681-3c6ba75d72a5', 'nest', 'The bird built a nest in the tree.', '鸟在树上筑了巢。'),
  ('28429ae2-40ff-4850-a681-3c6ba75d72a5-ex2', '28429ae2-40ff-4850-a681-3c6ba75d72a5', 'nest', 'The funds were nested through entity within entity to defeat tracing.', '这些资金通过层层嵌套的实体周转，以挫败追查。'),
  ('416e6d2e-d269-4acb-86a8-2ba7e846e2ea-ex1', '416e6d2e-d269-4acb-86a8-2ba7e846e2ea', 'thoroughly', 'Wash the vegetables thoroughly.', '把蔬菜彻底洗净。'),
  ('416e6d2e-d269-4acb-86a8-2ba7e846e2ea-ex2', '416e6d2e-d269-4acb-86a8-2ba7e846e2ea', 'thoroughly', 'The matter was thoroughly investigated before any charges were laid.', '在提出任何指控之前，此事经过了彻底调查。'),
  ('24020405-2445-458a-bd1c-8276f373d3a8-ex1', '24020405-2445-458a-bd1c-8276f373d3a8', 'lane', 'Stay in your lane while driving.', '开车时保持在自己的车道内。'),
  ('24020405-2445-458a-bd1c-8276f373d3a8-ex2', '24020405-2445-458a-bd1c-8276f373d3a8', 'lane', 'The merger eliminated the only meaningful competitor in that market lane.', '此次合并消灭了该细分市场中唯一有实质意义的竞争者。'),
  ('d7a1dd12-ac69-4117-af38-7843bdc3301c-ex1', 'd7a1dd12-ac69-4117-af38-7843bdc3301c', 'ancestor', 'Her ancestors came from Ireland.', '她的祖先来自爱尔兰。'),
  ('d7a1dd12-ac69-4117-af38-7843bdc3301c-ex2', 'd7a1dd12-ac69-4117-af38-7843bdc3301c', 'ancestor', 'The settlement recognizes indigenous title over ancestral territories.', '和解协议承认原住民对祖传领地的所有权。'),
  ('9f46d606-0702-4c32-95e7-881134f4f5f8-ex1', '9f46d606-0702-4c32-95e7-881134f4f5f8', 'condemn', 'We condemn all forms of violence.', '我们谴责一切形式的暴力。'),
  ('9f46d606-0702-4c32-95e7-881134f4f5f8-ex2', '9f46d606-0702-4c32-95e7-881134f4f5f8', 'condemn', 'The commission condemned the practice of awarding contracts without bidding.', '委员会谴责了不经招标就授予合同的做法。'),
  ('1a4aa704-a97f-4229-b23e-82e3fceb5c94-ex1', '1a4aa704-a97f-4229-b23e-82e3fceb5c94', 'steam', 'Steam rose from the hot soup.', '热汤冒着热气。'),
  ('1a4aa704-a97f-4229-b23e-82e3fceb5c94-ex2', '1a4aa704-a97f-4229-b23e-82e3fceb5c94', 'steam', 'The reform movement gathered steam as successive scandals eroded confidence.', '随着接连不断的丑闻侵蚀信心，改革运动声势日增。'),
  ('9d2fed3c-9fb0-4e83-8605-51bee54b2b1c-ex1', '9d2fed3c-9fb0-4e83-8605-51bee54b2b1c', 'accent', 'She speaks with a French accent.', '她说话带法国口音。'),
  ('9d2fed3c-9fb0-4e83-8605-51bee54b2b1c-ex2', '9d2fed3c-9fb0-4e83-8605-51bee54b2b1c', 'accent', 'The revised guidelines place renewed accent on proportionality.', '修订后的指南重新强调了相称性。'),
  ('ad4c2995-9d48-4274-9a5c-b904570b2124-ex1', 'ad4c2995-9d48-4274-9a5c-b904570b2124', 'optimistic', 'I feel optimistic about the future.', '我对未来感到乐观。'),
  ('ad4c2995-9d48-4274-9a5c-b904570b2124-ex2', 'ad4c2995-9d48-4274-9a5c-b904570b2124', 'optimistic', 'Even optimistic projections imply funding shortfalls within the decade.', '即使是乐观的预测也意味着十年内将出现资金缺口。'),
  ('588238ec-6f9a-4e15-b058-f5905412f5b4-ex1', '588238ec-6f9a-4e15-b058-f5905412f5b4', 'unite', 'The crisis united the community.', '危机使社区团结起来。'),
  ('588238ec-6f9a-4e15-b058-f5905412f5b4-ex2', '588238ec-6f9a-4e15-b058-f5905412f5b4', 'unite', 'The crisis united former adversaries in an unprecedented coalition.', '这场危机使昔日的对手结成了前所未有的联盟。'),
  ('35bf7140-d155-437d-84af-8da104cecc38-ex1', '35bf7140-d155-437d-84af-8da104cecc38', 'cage', 'The bird flew out of the cage.', '鸟从笼子里飞了出来。'),
  ('35bf7140-d155-437d-84af-8da104cecc38-ex2', '35bf7140-d155-437d-84af-8da104cecc38', 'cage', 'The reforms rattled the cage of an industry long accustomed to deference.', '这些改革震动了一个长期习惯于被宽待的行业。'),
  ('63abf409-78f3-4b7f-84f9-fee6627d54e8-ex1', '63abf409-78f3-4b7f-84f9-fee6627d54e8', 'equip', 'The kitchen is equipped with new tools.', '厨房配备了新工具。'),
  ('63abf409-78f3-4b7f-84f9-fee6627d54e8-ex2', '63abf409-78f3-4b7f-84f9-fee6627d54e8', 'equip', 'The agency was poorly equipped to administer the expanded mandate.', '该机构在履行扩大后的职权方面准备不足。'),
  ('de1e2926-4be2-44a5-ab58-5e45c6d018c2-ex1', 'de1e2926-4be2-44a5-ab58-5e45c6d018c2', 'shrimp', 'We had grilled shrimp for dinner.', '我们晚餐吃了烤虾。'),
  ('de1e2926-4be2-44a5-ab58-5e45c6d018c2-ex2', 'de1e2926-4be2-44a5-ab58-5e45c6d018c2', 'shrimp', 'The import standards apply to every shrimp consignment entering the market.', '进口标准适用于进入市场的每一批虾。'),
  ('afd1ff7c-0e4f-4cb8-918d-7aa5e3ebe6bb-ex1', 'afd1ff7c-0e4f-4cb8-918d-7aa5e3ebe6bb', 'homeland', 'They returned to their homeland.', '他们回到了祖国。'),
  ('afd1ff7c-0e4f-4cb8-918d-7aa5e3ebe6bb-ex2', 'afd1ff7c-0e4f-4cb8-918d-7aa5e3ebe6bb', 'homeland', 'The convention prohibits returning a refugee to a homeland where persecution awaits.', '该公约禁止将难民遣返至会遭受迫害的祖国。'),
  ('0f932022-f002-4d34-b8da-9ef85cec56ea-ex1', '0f932022-f002-4d34-b8da-9ef85cec56ea', 'rack', 'Hang your coat on the rack.', '把外套挂在衣架上。'),
  ('0f932022-f002-4d34-b8da-9ef85cec56ea-ex2', '0f932022-f002-4d34-b8da-9ef85cec56ea', 'rack', 'The losses racked up faster than the board could comprehend their scale.', '亏损累积的速度超过了董事会理解其规模的速度。'),
  ('a73048b7-8c89-42e5-99eb-ff73f76eb7f8-ex1', 'a73048b7-8c89-42e5-99eb-ff73f76eb7f8', 'costume', 'She wore a colorful costume.', '她穿着一套色彩鲜艳的服装。'),
  ('a73048b7-8c89-42e5-99eb-ff73f76eb7f8-ex2', 'a73048b7-8c89-42e5-99eb-ff73f76eb7f8', 'costume', 'The seized costumes bore counterfeit marks of a protected franchise.', '查获的服装带有受保护品牌的假冒标识。'),
  ('6adc36a6-0056-4107-9e38-fdf8e9aeb256-ex1', '6adc36a6-0056-4107-9e38-fdf8e9aeb256', 'wolf', 'A wolf howled in the distance.', '远处有狼嗥叫。'),
  ('6adc36a6-0056-4107-9e38-fdf8e9aeb256-ex2', '6adc36a6-0056-4107-9e38-fdf8e9aeb256', 'wolf', 'The scheme was a wolf in sheep''s clothing, marketed as conservative yet wildly speculative.', '这个方案是披着羊皮的狼，号称稳健实则极度投机。'),
  ('a569ffcc-c04e-4b77-8b8c-e9efc1a086f0-ex1', 'a569ffcc-c04e-4b77-8b8c-e9efc1a086f0', 'courtroom', 'The courtroom was silent.', '法庭里一片寂静。'),
  ('a569ffcc-c04e-4b77-8b8c-e9efc1a086f0-ex2', 'a569ffcc-c04e-4b77-8b8c-e9efc1a086f0', 'courtroom', 'The courtroom drama obscured the technical questions at the heart of the case.', '庭审的戏剧性掩盖了案件核心的技术问题。'),
  ('6045576a-0d31-4b9d-9734-c3ceccd20889-ex1', '6045576a-0d31-4b9d-9734-c3ceccd20889', 'statute', 'The statute was passed last year.', '这项法规去年获得通过。'),
  ('6045576a-0d31-4b9d-9734-c3ceccd20889-ex2', '6045576a-0d31-4b9d-9734-c3ceccd20889', 'statute', 'The court construed the statute narrowly to preserve legislative intent.', '法院对该法规作狭义解释，以维护立法意图。'),
  ('c29f3091-8117-49f3-adee-00d9949e5fe5-ex1', 'c29f3091-8117-49f3-adee-00d9949e5fe5', 'cartoon', 'The kids watched a cartoon.', '孩子们看了一部动画片。'),
  ('c29f3091-8117-49f3-adee-00d9949e5fe5-ex2', 'c29f3091-8117-49f3-adee-00d9949e5fe5', 'cartoon', 'The political cartoon was defended as protected satirical expression.', '这幅政治漫画被辩护为受保护的讽刺性表达。'),
  ('1d28e807-a86c-4bae-aad3-ade8882f87b5-ex1', '1d28e807-a86c-4bae-aad3-ade8882f87b5', 'productivity', 'The new tools improved productivity.', '新工具提高了生产力。'),
  ('1d28e807-a86c-4bae-aad3-ade8882f87b5-ex2', '1d28e807-a86c-4bae-aad3-ade8882f87b5', 'productivity', 'Measured productivity rose even as real wages stagnated.', '即使实际工资停滞，测量到的生产率仍在上升。'),
  ('c676f1a1-bc2e-4018-81d2-e391d1f75579-ex1', 'c676f1a1-bc2e-4018-81d2-e391d1f75579', 'grin', 'He had a wide grin on his face.', '他脸上咧着大大的笑容。'),
  ('c676f1a1-bc2e-4018-81d2-e391d1f75579-ex2', 'c676f1a1-bc2e-4018-81d2-e391d1f75579', 'grin', 'The board could only grin and bear the structural remedy imposed.', '董事会只能强颜欢笑，接受所施加的结构性救济。'),
  ('c926047f-5e06-4715-a613-7a7d6f6944ca-ex1', 'c926047f-5e06-4715-a613-7a7d6f6944ca', 'symbolic', 'The gift had a symbolic meaning.', '这份礼物具有象征意义。'),
  ('c926047f-5e06-4715-a613-7a7d6f6944ca-ex2', 'c926047f-5e06-4715-a613-7a7d6f6944ca', 'symbolic', 'The concession was symbolic, devoid of any binding effect.', '这一让步只是象征性的，没有任何约束力。'),
  ('4fd95fad-c934-4883-8009-3cf9ff7224cd-ex1', '4fd95fad-c934-4883-8009-3cf9ff7224cd', 'bug', 'There is a bug in the software.', '软件里有个漏洞。'),
  ('4fd95fad-c934-4883-8009-3cf9ff7224cd-ex2', '4fd95fad-c934-4883-8009-3cf9ff7224cd', 'bug', 'The defect was no mere bug but a structural flaw in the design.', '这一缺陷并非小漏洞，而是设计上的结构性缺陷。'),
  ('04d80ef9-38d2-49e4-8088-17d664e1dbc0-ex1', '04d80ef9-38d2-49e4-8088-17d664e1dbc0', 'bless', 'The priest blessed the couple.', '神父为这对新人祝福。'),
  ('04d80ef9-38d2-49e4-8088-17d664e1dbc0-ex2', '04d80ef9-38d2-49e4-8088-17d664e1dbc0', 'bless', 'The committee gave its blessing to the merger subject to behavioral remedies.', '委员会附带行为性救济条件，对合并表示认可。'),
  ('58275226-f7f0-4378-8859-9170494c2b23-ex1', '58275226-f7f0-4378-8859-9170494c2b23', 'aunt', 'My aunt lives next door.', '我姑姑住在隔壁。'),
  ('58275226-f7f0-4378-8859-9170494c2b23-ex2', '58275226-f7f0-4378-8859-9170494c2b23', 'aunt', 'The court recognized the aunt''s standing as a beneficiary under the trust.', '法院承认这位姑姑作为信托受益人的资格。'),
  ('27fdf841-13bc-4080-86cd-25361dedf284-ex1', '27fdf841-13bc-4080-86cd-25361dedf284', 'agriculture', 'Agriculture is important here.', '农业在这里很重要。'),
  ('27fdf841-13bc-4080-86cd-25361dedf284-ex2', '27fdf841-13bc-4080-86cd-25361dedf284', 'agriculture', 'The accord secured safeguards for agriculture in developing economies.', '该协定为发展中经济体的农业争取到了保障条款。'),
  ('9c287ae8-fc00-4cb7-b7ad-3b5fd24457bd-ex1', '9c287ae8-fc00-4cb7-b7ad-3b5fd24457bd', 'hostile', 'The crowd grew hostile.', '人群变得充满敌意。'),
  ('9c287ae8-fc00-4cb7-b7ad-3b5fd24457bd-ex2', '9c287ae8-fc00-4cb7-b7ad-3b5fd24457bd', 'hostile', 'The board adopted defensive measures to repel the hostile takeover bid.', '董事会采取防御措施以击退敌意收购要约。'),
  ('07aa40d3-81fd-49a9-bdbb-9f6fd191c6ec-ex1', '07aa40d3-81fd-49a9-bdbb-9f6fd191c6ec', 'conceive', 'I cannot conceive of such cruelty.', '我无法想象如此残忍的行为。'),
  ('07aa40d3-81fd-49a9-bdbb-9f6fd191c6ec-ex2', '07aa40d3-81fd-49a9-bdbb-9f6fd191c6ec', 'conceive', 'Few could conceive the institutional transformations the decade would bring.', '很少有人能想象这十年将带来的制度变革。'),
  ('05f36a53-b629-4e24-8b67-f4c0db5228ac-ex1', '05f36a53-b629-4e24-8b67-f4c0db5228ac', 'combined', 'Their combined effort paid off.', '他们的共同努力得到了回报。'),
  ('05f36a53-b629-4e24-8b67-f4c0db5228ac-ex2', '05f36a53-b629-4e24-8b67-f4c0db5228ac', 'combined', 'The combined exposure of the two entities exceeded prudential limits.', '这两个实体的合并风险敞口超过了审慎限额。'),
  ('201547b5-65b9-4ab1-ab6c-f7479d14edbc-ex1', '201547b5-65b9-4ab1-ab6c-f7479d14edbc', 'instantly', 'She recognized him instantly.', '她一眼就认出了他。'),
  ('201547b5-65b9-4ab1-ab6c-f7479d14edbc-ex2', '201547b5-65b9-4ab1-ab6c-f7479d14edbc', 'instantly', 'In an interconnected market, a localized shock propagates almost instantly.', '在互联互通的市场中，局部冲击几乎瞬间扩散。'),
  ('392e4df8-a9c4-4300-b8bc-cc4bdbee5057-ex1', '392e4df8-a9c4-4300-b8bc-cc4bdbee5057', 'bankruptcy', 'The company filed for bankruptcy.', '该公司申请了破产。'),
  ('392e4df8-a9c4-4300-b8bc-cc4bdbee5057-ex2', '392e4df8-a9c4-4300-b8bc-cc4bdbee5057', 'bankruptcy', 'The bankruptcy distribution follows the statutory order of priority.', '破产分配遵循法定清偿顺序。'),
  ('ab05ce56-67f4-4f39-a629-0e1ca93cc131-ex1', 'ab05ce56-67f4-4f39-a629-0e1ca93cc131', 'vaccine', 'The vaccine prevents the disease.', '这种疫苗能预防该疾病。'),
  ('ab05ce56-67f4-4f39-a629-0e1ca93cc131-ex2', 'ab05ce56-67f4-4f39-a629-0e1ca93cc131', 'vaccine', 'The consortium was formed to develop vaccines against pandemic pathogens.', '该联盟的成立旨在研发针对大流行病原体的疫苗。'),
  ('8f9f71de-c315-45e0-9163-341c2c4a7929-ex1', '8f9f71de-c315-45e0-9163-341c2c4a7929', 'bonus', 'She received a year-end bonus.', '她拿到了年终奖。'),
  ('8f9f71de-c315-45e0-9163-341c2c4a7929-ex2', '8f9f71de-c315-45e0-9163-341c2c4a7929', 'bonus', 'Executive bonuses are now linked explicitly to long-term performance.', '高管奖金现已与长期业绩明确挂钩。'),
  ('d1845e3f-0a4c-4373-9738-324d54675785-ex1', 'd1845e3f-0a4c-4373-9738-324d54675785', 'collaboration', 'The project was a collaboration.', '这个项目是合作的产物。'),
  ('d1845e3f-0a4c-4373-9738-324d54675785-ex2', 'd1845e3f-0a4c-4373-9738-324d54675785', 'collaboration', 'The accord opens the door to unprecedented scientific collaboration.', '该协议为前所未有的科学合作打开了大门。'),
  ('7bf7c72d-f28e-412c-8496-178c6a64d73b-ex1', '7bf7c72d-f28e-412c-8496-178c6a64d73b', 'mixed', 'I have mixed feelings about it.', '我对此心情复杂。'),
