  ('98c929d8-e337-49c5-b6c3-28a08c1e787b-ex1', '98c929d8-e337-49c5-b6c3-28a08c1e787b', 'sheep', 'The farmer keeps sheep.', '这位农民养羊。'),
  ('98c929d8-e337-49c5-b6c3-28a08c1e787b-ex2', '98c929d8-e337-49c5-b6c3-28a08c1e787b', 'sheep', 'The scheme was a wolf in sheep''s clothing dressed up as conservative.', '这个方案是披着羊皮的狼，包装成稳健的样子。'),
