  ('566fd89d-f9f1-405c-95da-8f98b33869f2-ex1', '566fd89d-f9f1-405c-95da-8f98b33869f2', 'aboard', 'All passengers are aboard.', '所有乘客都上船了。'),
  ('566fd89d-f9f1-405c-95da-8f98b33869f2-ex2', '566fd89d-f9f1-405c-95da-8f98b33869f2', 'aboard', 'The flag state bears responsibility for everyone aboard the registered vessel.', '船旗国对登记船舶上的每个人负有责任。'),
  ('faf9740e-14e7-4658-b3bd-93a99de51ac9-ex1', 'faf9740e-14e7-4658-b3bd-93a99de51ac9', 'booth', 'We sat in a corner booth.', '我们坐在角落的卡座里。'),
  ('faf9740e-14e7-4658-b3bd-93a99de51ac9-ex2', 'faf9740e-14e7-4658-b3bd-93a99de51ac9', 'booth', 'Each voter marks the ballot privately within the polling booth.', '每位选民在投票间内私下填写选票。'),
  ('1758cddb-318c-4bb5-b956-c39aa29e347e-ex1', '1758cddb-318c-4bb5-b956-c39aa29e347e', 'helmet', 'Always wear a helmet when cycling.', '骑车时一定要戴头盔。'),
  ('1758cddb-318c-4bb5-b956-c39aa29e347e-ex2', '1758cddb-318c-4bb5-b956-c39aa29e347e', 'helmet', 'The safety code mandates certified helmets for all personnel on site.', '安全规范要求现场所有人员佩戴经认证的头盔。'),
