  ('c8f9a1fa-7f3c-47f9-843d-5b9c0797c726-ex2', 'c8f9a1fa-7f3c-47f9-843d-5b9c0797c726', 'copyright', 'The work entered the public domain upon expiry of the copyright term.', '作品在版权期满后进入了公有领域。'),
  ('bee776cd-491f-46ee-91b4-6686f18e768b-ex1', 'bee776cd-491f-46ee-91b4-6686f18e768b', 'breach', 'The breach of contract cost them money.', '违约让他们损失了钱。'),
  ('bee776cd-491f-46ee-91b4-6686f18e768b-ex2', 'bee776cd-491f-46ee-91b4-6686f18e768b', 'breach', 'Such conduct constitutes a material breach entitling immediate termination.', '此类行为构成允许立即终止合同的重大违约。'),
  ('c663d45e-3c6f-4073-9ce2-c98c8515d7ae-ex1', 'c663d45e-3c6f-4073-9ce2-c98c8515d7ae', 'shy', 'The little boy is very shy.', '这个小男孩很害羞。'),
  ('c663d45e-3c6f-4073-9ce2-c98c8515d7ae-ex2', 'c663d45e-3c6f-4073-9ce2-c98c8515d7ae', 'shy', 'The agency fell shy of its statutory obligations in several respects.', '该机构在若干方面未能履行其法定义务。'),
  ('0388f1d9-1dfe-4eb3-86f9-80bd568a10c6-ex1', '0388f1d9-1dfe-4eb3-86f9-80bd568a10c6', 'clause', 'Read every clause of the contract.', '阅读合同的每一项条款。'),
  ('0388f1d9-1dfe-4eb3-86f9-80bd568a10c6-ex2', '0388f1d9-1dfe-4eb3-86f9-80bd568a10c6', 'clause', 'The entire appeal turns on the construction of a single contractual clause.', '整个上诉的成败系于一项合同条款的解释。'),
  ('ab54adf0-f91a-4f71-a765-e3e32531bd9d-ex1', 'ab54adf0-f91a-4f71-a765-e3e32531bd9d', 'trash', 'Take the trash out, please.', '请把垃圾倒掉。'),
  ('ab54adf0-f91a-4f71-a765-e3e32531bd9d-ex2', 'ab54adf0-f91a-4f71-a765-e3e32531bd9d', 'trash', 'Critics trashed the proposal as fiscally reckless and administratively naive.', '批评者抨击该提案在财政上鲁莽、在行政上天真。'),
  ('f54e5566-d5c2-4947-8521-c14f76ffb2e0-ex1', 'f54e5566-d5c2-4947-8521-c14f76ffb2e0', 'warrant', 'The police obtained a search warrant.', '警方取得了搜查令。'),
  ('f54e5566-d5c2-4947-8521-c14f76ffb2e0-ex2', 'f54e5566-d5c2-4947-8521-c14f76ffb2e0', 'warrant', 'The evidence did not warrant escalation to formal enforcement.', '这些证据尚不足以升级为正式执法。'),
  ('19287e61-c592-4740-9d8a-c29efc12f0f4-ex1', '19287e61-c592-4740-9d8a-c29efc12f0f4', 'disabled', 'The ramp helps disabled visitors.', '坡道方便残障访客。'),
  ('19287e61-c592-4740-9d8a-c29efc12f0f4-ex2', '19287e61-c592-4740-9d8a-c29efc12f0f4', 'disabled', 'The act mandates reasonable accommodation for disabled employees.', '该法案要求为残障雇员作出合理便利安排。'),
  ('bfc623c9-836b-445f-b56f-ccd4a0f0efb4-ex1', 'bfc623c9-836b-445f-b56f-ccd4a0f0efb4', 'tribunal', 'The tribunal heard the case.', '法庭审理了此案。'),
  ('bfc623c9-836b-445f-b56f-ccd4a0f0efb4-ex2', 'bfc623c9-836b-445f-b56f-ccd4a0f0efb4', 'tribunal', 'The tribunal annulled the award for fundamental defects in procedure.', '法庭以程序存在根本缺陷为由撤销了该裁决。'),
  ('69a665ac-86c2-45c9-8459-4d011741ee69-ex1', '69a665ac-86c2-45c9-8459-4d011741ee69', 'gross', 'The gross weight includes packaging.', '毛重包含包装。'),
  ('69a665ac-86c2-45c9-8459-4d011741ee69-ex2', '69a665ac-86c2-45c9-8459-4d011741ee69', 'gross', 'The levy is calculated on gross revenue rather than net profit.', '该税费按总收入而非净利润计征。'),
  ('8e2e4b2d-052b-494a-954e-b4bb10a68be1-ex1', '8e2e4b2d-052b-494a-954e-b4bb10a68be1', 'prosecute', 'They will prosecute the offender.', '他们将起诉违法者。'),
  ('8e2e4b2d-052b-494a-954e-b4bb10a68be1-ex2', '8e2e4b2d-052b-494a-954e-b4bb10a68be1', 'prosecute', 'The agency elected to prosecute the matter rather than pursue civil remedies.', '该机构选择对此事提起刑事诉讼，而非寻求民事救济。'),
  ('180f7dfa-cfc8-4563-8123-8f124b4d53e9-ex1', '180f7dfa-cfc8-4563-8123-8f124b4d53e9', 'damn', '"Damn," he said, dropping the cup.', '“该死，”他说着，杯子掉了。'),
  ('180f7dfa-cfc8-4563-8123-8f124b4d53e9-ex2', '180f7dfa-cfc8-4563-8123-8f124b4d53e9', 'damn', 'The figures painted a damning portrait of sustained regulatory complacency.', '这些数字勾勒出一幅监管长期自满的可悲图景。'),
  ('46236a8b-a292-42b5-8aca-4e5095eb6d3e-ex1', '46236a8b-a292-42b5-8aca-4e5095eb6d3e', 'amend', 'They voted to amend the rule.', '他们投票修改了规则。'),
  ('46236a8b-a292-42b5-8aca-4e5095eb6d3e-ex2', '46236a8b-a292-42b5-8aca-4e5095eb6d3e', 'amend', 'The legislature moved to amend the statute to close the identified loophole.', '立法机关着手修订法规，以堵塞已发现的漏洞。'),
  ('3228cb8b-91c4-4f8d-8b70-080f02dfdb0e-ex1', '3228cb8b-91c4-4f8d-8b70-080f02dfdb0e', 'arbitrate', 'A neutral party will arbitrate.', '将由中立方进行仲裁。'),
  ('3228cb8b-91c4-4f8d-8b70-080f02dfdb0e-ex2', '3228cb8b-91c4-4f8d-8b70-080f02dfdb0e', 'arbitrate', 'The tribunal is empowered to arbitrate disputes arising under the agreement.', '该法庭有权仲裁依据本协议产生的争议。'),
  ('feff867a-1432-4c0d-9064-8abcdffb4645-ex1', 'feff867a-1432-4c0d-9064-8abcdffb4645', 'hormone', 'Hormones affect your mood.', '激素会影响你的情绪。'),
  ('feff867a-1432-4c0d-9064-8abcdffb4645-ex2', 'feff867a-1432-4c0d-9064-8abcdffb4645', 'hormone', 'The regulation restricts hormone treatments marketed without clinical validation.', '该法规限制未经临床验证而推销的激素疗法。'),
  ('6b06b1df-964c-4f99-b97c-ac55f8666368-ex1', '6b06b1df-964c-4f99-b97c-ac55f8666368', 'texture', 'The fabric has a soft texture.', '这种布料质地柔软。'),
  ('6b06b1df-964c-4f99-b97c-ac55f8666368-ex2', '6b06b1df-964c-4f99-b97c-ac55f8666368', 'texture', 'The scandal frayed the texture of trust underpinning the institution.', '这桩丑闻撕裂了支撑该机构的信任肌理。'),
  ('86cfcc1a-b137-4031-9f6c-784ee68d01ee-ex1', '86cfcc1a-b137-4031-9f6c-784ee68d01ee', 'bail', 'He was released on bail.', '他被保释了。'),
  ('86cfcc1a-b137-4031-9f6c-784ee68d01ee-ex2', '86cfcc1a-b137-4031-9f6c-784ee68d01ee', 'bail', 'The court denied bail given the demonstrable risk of flight.', '鉴于明显存在潜逃风险，法院拒绝了保释。'),
  ('4b082fbb-1757-42cc-bf1e-f38f3c859a93-ex1', '4b082fbb-1757-42cc-bf1e-f38f3c859a93', 'decree', 'The king issued a decree.', '国王颁布了一道法令。'),
  ('4b082fbb-1757-42cc-bf1e-f38f3c859a93-ex2', '4b082fbb-1757-42cc-bf1e-f38f3c859a93', 'decree', 'The emergency decree suspended ordinary procurement safeguards.', '紧急法令暂停了常规采购保障程序。'),
  ('8c809ca1-4975-4bef-908c-2bf6d7b2c57f-ex1', '8c809ca1-4975-4bef-908c-2bf6d7b2c57f', 'detain', 'The guard detained the suspect.', '警卫扣留了嫌疑人。'),
  ('8c809ca1-4975-4bef-908c-2bf6d7b2c57f-ex2', '8c809ca1-4975-4bef-908c-2bf6d7b2c57f', 'detain', 'Authorities may not detain a person beyond the statutory period without charge.', '当局不得在未提出指控的情况下将人羁押超过法定期限。')
